Qed.

Lemma HF_pairSuccStepAt_free : forall i f m,
  Free i (HF_pairSuccStepAt f m) -> i = f \/ i = m.
Proof.
  intros i f m h.
  unfold HF_pairSuccStepAt, HF_pairMemAt, HF_kpairAt,
    HF_singleAt, HF_upairAt, HF_succAt, HF_adjoinAt, fIff in h.
