Lemma HF_pairBaseAt_free : forall i f s,
  Free i (HF_pairBaseAt f s) -> i = f \/ i = s.
Proof.
  intros i f s h.
  unfold HF_pairBaseAt, HF_emptyAt, HF_pairMemAt, HF_kpairAt,
