Lemma HF_pairZeroBaseAt_free : forall i f,
  Free i (HF_pairZeroBaseAt f) -> i = f.
Proof.
  intros i f h.
  unfold HF_pairZeroBaseAt, HF_emptyAt, HF_pairMemAt, HF_kpairAt,
