Proof.
  intros sigma G.
  induction G as [|phi G IH]; simpl.
  - reflexivity.
  - rewrite subst_rename_succ_up.
    rewrite IH.
    reflexivity.
Qed.

Lemma Sat_instTerm : forall (M : Model) phi t (e : nat -> M),
  Sat M e (subst (instTerm t) phi) <->
    Sat M (scons M (Term.eval M e t) e) phi.
Proof.
  intros M phi t e.
  eapply iff_trans.
  - apply Sat_subst.
  - apply Sat_ext.
    intros [|n]; reflexivity.
Qed.

Inductive Prov : list formula -> formula -> Prop :=
| P_ass : forall G a, In a G -> Prov G a
| P_impI : forall G a b, Prov (a :: G) b -> Prov G (pImp a b)
| P_impE : forall G a b, Prov G (pImp a b) -> Prov G a -> Prov G b
| P_botE : forall G a, Prov G pBot -> Prov G a
| P_lem : forall G a, Prov G (pOr a (pImp a pBot))
| P_andI : forall G a b, Prov G a -> Prov G b -> Prov G (pAnd a b)
| P_andE1 : forall G a b, Prov G (pAnd a b) -> Prov G a
| P_andE2 : forall G a b, Prov G (pAnd a b) -> Prov G b
| P_orI1 : forall G a b, Prov G a -> Prov G (pOr a b)
| P_orI2 : forall G a b, Prov G b -> Prov G (pOr a b)
| P_orE : forall G a b c,
    Prov G (pOr a b) ->
    Prov (a :: G) c ->
    Prov (b :: G) c ->
    Prov G c
| P_allI : forall G a,
    Prov (map (rename S) G) a ->
    Prov G (pAll a)
| P_allE : forall G a t,
    Prov G (pAll a) ->
    Prov G (subst (instTerm t) a)
| P_exI : forall G a t,
    Prov G (subst (instTerm t) a) ->
    Prov G (pEx a)
| P_exE : forall G a c,
    Prov G (pEx a) ->
    Prov (a :: map (rename S) G) (rename S c) ->
    Prov G c
| P_eqRefl : forall G t, Prov G (pEq t t)
| P_eqElim : forall G s t a,
    Prov G (pEq s t) ->
    Prov G (subst (instTerm s) a) ->
    Prov G (subst (instTerm t) a).

Lemma cons_sub : forall (a : formula) (G G' : list formula),
  (forall x, In x G -> In x G') ->
  forall x, In x (a :: G) -> In x (a :: G').
Proof.
  intros a G G' hsub x hx.
  simpl in hx |- *.
  destruct hx as [hx | hx].
  - left. exact hx.
  - right. exact (hsub x hx).
Qed.

Lemma mem_map_sub : forall (f : formula -> formula) (G G' : list formula),
  (forall x, In x G -> In x G') ->
  forall x, In x (map f G) -> In x (map f G').
Proof.
  intros f G G' hsub x hx.
  apply in_map_iff in hx.
  destruct hx as [y [hy hx]].
  subst x.
  apply in_map.
  exact (hsub y hx).
Qed.

Lemma Prov_weaken : forall G a,
  Prov G a ->
  forall G', (forall x, In x G -> In x G') -> Prov G' a.
Proof.
  intros G a h.
  induction h; intros G' hsub.
  - exact (P_ass G' a (hsub a H)).
  - exact (P_impI G' a b (IHh (a :: G') (cons_sub a G G' hsub))).
  - exact (P_impE G' a b (IHh1 G' hsub) (IHh2 G' hsub)).
  - exact (P_botE G' a (IHh G' hsub)).
  - exact (P_lem G' a).
  - exact (P_andI G' a b (IHh1 G' hsub) (IHh2 G' hsub)).
  - exact (P_andE1 G' a b (IHh G' hsub)).
  - exact (P_andE2 G' a b (IHh G' hsub)).
  - exact (P_orI1 G' a b (IHh G' hsub)).
  - exact (P_orI2 G' a b (IHh G' hsub)).
  - exact (P_orE G' a b c (IHh1 G' hsub)
      (IHh2 (a :: G') (cons_sub a G G' hsub))
      (IHh3 (b :: G') (cons_sub b G G' hsub))).
  - exact (P_allI G' a (IHh (map (rename S) G')
      (mem_map_sub (rename S) G G' hsub))).
  - exact (P_allE G' a t (IHh G' hsub)).
  - exact (P_exI G' a t (IHh G' hsub)).
  - exact (P_exE G' a c (IHh1 G' hsub)
      (IHh2 (a :: map (rename S) G')
        (cons_sub a (map (rename S) G) (map (rename S) G')
          (mem_map_sub (rename S) G G' hsub)))).
  - exact (P_eqRefl G' t).
  - exact (P_eqElim G' s t a (IHh1 G' hsub) (IHh2 G' hsub)).
Qed.

Lemma Prov_cons : forall G a b,
  Prov G b -> Prov (a :: G) b.
Proof.
  intros G a b h.
  apply (Prov_weaken G b h).
  intros x hx.
  simpl. right. exact hx.
Qed.

Lemma map_rename_up_succ : forall (r : nat -> nat) G,
  map (rename (up r)) (map (rename S) G) =
    map (rename S) (map (rename r) G).
Proof.
  intros r G.
  induction G as [|phi G IH]; simpl.
  - reflexivity.
  - rewrite rename_up_succ.
    rewrite IH.
    reflexivity.
Qed.

Lemma Prov_rename : forall G phi,
  Prov G phi -> forall r,
  Prov (map (rename r) G) (rename r phi).
Proof.
  intros G phi h.
  induction h; intro r; simpl.
  - apply P_ass.
    apply in_map.
    exact H.
  - apply P_impI.
    exact (IHh r).
  - exact (P_impE (map (rename r) G) (rename r a) (rename r b)
      (IHh1 r) (IHh2 r)).
  - exact (P_botE (map (rename r) G) (rename r a) (IHh r)).
  - exact (P_lem (map (rename r) G) (rename r a)).
  - exact (P_andI (map (rename r) G) (rename r a) (rename r b)
      (IHh1 r) (IHh2 r)).
  - exact (P_andE1 (map (rename r) G) (rename r a) (rename r b)
      (IHh r)).
  - exact (P_andE2 (map (rename r) G) (rename r a) (rename r b)
      (IHh r)).
  - exact (P_orI1 (map (rename r) G) (rename r a) (rename r b)
      (IHh r)).
  - exact (P_orI2 (map (rename r) G) (rename r a) (rename r b)
      (IHh r)).
  - exact (P_orE (map (rename r) G) (rename r a) (rename r b)
      (rename r c) (IHh1 r) (IHh2 r) (IHh3 r)).
  - apply P_allI.
    rewrite <- map_rename_up_succ.
    exact (IHh (up r)).
  - rewrite <- subst_instTerm_rename_up.
    exact (P_allE (map (rename r) G) (rename (up r) a)
      (Term.rename r t) (IHh r)).
  - apply (P_exI (map (rename r) G) (rename (up r) a)
      (Term.rename r t)).
    rewrite subst_instTerm_rename_up.
    exact (IHh r).
  - assert (hEx : Prov (map (rename r) G) (pEx (rename (up r) a))).
    {
      exact (IHh1 r).
    }
    assert (hbody :
        Prov (rename (up r) a :: map (rename S) (map (rename r) G))
          (rename S (rename r c))).
    {
      rewrite <- map_rename_up_succ.
      rewrite <- rename_up_succ.
      change (Prov (map (rename (up r)) (a :: map (rename S) G))
        (rename (up r) (rename S c))).
      exact (IHh2 (up r)).
    }
    exact (P_exE (map (rename r) G) (rename (up r) a) (rename r c)
      hEx hbody).
  - exact (P_eqRefl (map (rename r) G) (Term.rename r t)).
  - assert (hEq :
        Prov (map (rename r) G)
          (pEq (Term.rename r s) (Term.rename r t))).
    {
      exact (IHh1 r).
    }
    assert (hA :
        Prov (map (rename r) G)
          (subst (instTerm (Term.rename r s)) (rename (up r) a))).
    {
      rewrite subst_instTerm_rename_up.
      exact (IHh2 r).
    }
    pose proof (P_eqElim (map (rename r) G)
      (Term.rename r s) (Term.rename r t) (rename (up r) a)
      hEq hA) as hElim.
    rewrite subst_instTerm_rename_up in hElim.
    exact hElim.
Qed.

Lemma Prov_subst : forall G phi,
  Prov G phi -> forall sigma,
  Prov (map (subst sigma) G) (subst sigma phi).
Proof.
  intros G phi h.
  induction h; intro sigma; simpl.
  - apply P_ass.
    apply in_map.
    exact H.
  - apply P_impI.
    exact (IHh sigma).
  - exact (P_impE (map (subst sigma) G) (subst sigma a)
      (subst sigma b) (IHh1 sigma) (IHh2 sigma)).
  - exact (P_botE (map (subst sigma) G) (subst sigma a) (IHh sigma)).
  - exact (P_lem (map (subst sigma) G) (subst sigma a)).
  - exact (P_andI (map (subst sigma) G) (subst sigma a)
      (subst sigma b) (IHh1 sigma) (IHh2 sigma)).
  - exact (P_andE1 (map (subst sigma) G) (subst sigma a)
      (subst sigma b) (IHh sigma)).
  - exact (P_andE2 (map (subst sigma) G) (subst sigma a)
      (subst sigma b) (IHh sigma)).
  - exact (P_orI1 (map (subst sigma) G) (subst sigma a)
      (subst sigma b) (IHh sigma)).
  - exact (P_orI2 (map (subst sigma) G) (subst sigma a)
      (subst sigma b) (IHh sigma)).
  - exact (P_orE (map (subst sigma) G) (subst sigma a)
      (subst sigma b) (subst sigma c)
      (IHh1 sigma) (IHh2 sigma) (IHh3 sigma)).
  - apply P_allI.
    rewrite <- map_subst_rename_succ_up.
    exact (IHh (Term.upSubst sigma)).
  - rewrite <- subst_instTerm_subst_up.
    exact (P_allE (map (subst sigma) G) (subst (Term.upSubst sigma) a)
      (Term.subst sigma t) (IHh sigma)).
  - apply (P_exI (map (subst sigma) G) (subst (Term.upSubst sigma) a)
      (Term.subst sigma t)).
    rewrite subst_instTerm_subst_up.
    exact (IHh sigma).
  - assert (hEx : Prov (map (subst sigma) G)
        (pEx (subst (Term.upSubst sigma) a))).
    {
      exact (IHh1 sigma).
    }
    assert (hbody :
        Prov (subst (Term.upSubst sigma) a ::
            map (rename S) (map (subst sigma) G))
          (rename S (subst sigma c))).
    {
      rewrite <- map_subst_rename_succ_up.
      rewrite <- subst_rename_succ_up.
      change (Prov (map (subst (Term.upSubst sigma))
          (a :: map (rename S) G))
        (subst (Term.upSubst sigma) (rename S c))).
      exact (IHh2 (Term.upSubst sigma)).
    }
    exact (P_exE (map (subst sigma) G) (subst (Term.upSubst sigma) a)
      (subst sigma c) hEx hbody).
  - exact (P_eqRefl (map (subst sigma) G) (Term.subst sigma t)).
  - assert (hEq :
        Prov (map (subst sigma) G)
          (pEq (Term.subst sigma s) (Term.subst sigma t))).
    {
      exact (IHh1 sigma).
    }
    assert (hA :
        Prov (map (subst sigma) G)
          (subst (instTerm (Term.subst sigma s))
            (subst (Term.upSubst sigma) a))).
    {
      rewrite subst_instTerm_subst_up.
      exact (IHh2 sigma).
    }
    pose proof (P_eqElim (map (subst sigma) G)
      (Term.subst sigma s) (Term.subst sigma t)
      (subst (Term.upSubst sigma) a) hEq hA) as hElim.
    rewrite subst_instTerm_subst_up in hElim.
    exact hElim.
Qed.

Lemma Prov_cut : forall G phi,
  Prov G phi ->
  forall De, (forall x, In x G -> Prov De x) -> Prov De phi.
Proof.
  intros G phi h.
  induction h; intros De hD.
  - exact (hD a H).
  - apply P_impI.
    apply IHh.
    intros x hx.
    simpl in hx.
    destruct hx as [hx | hx].
    + subst x.
      apply P_ass. simpl. left. reflexivity.
    + apply Prov_cons.
      exact (hD x hx).
  - exact (P_impE De a b (IHh1 De hD) (IHh2 De hD)).
  - exact (P_botE De a (IHh De hD)).
  - exact (P_lem De a).
  - exact (P_andI De a b (IHh1 De hD) (IHh2 De hD)).
  - exact (P_andE1 De a b (IHh De hD)).
  - exact (P_andE2 De a b (IHh De hD)).
  - exact (P_orI1 De a b (IHh De hD)).
  - exact (P_orI2 De a b (IHh De hD)).
  - apply (P_orE De a b c (IHh1 De hD)).
    + apply IHh2.
      intros x hx.
      simpl in hx.
      destruct hx as [hx | hx].
      * subst x.
        apply P_ass. simpl. left. reflexivity.
      * apply Prov_cons.
        exact (hD x hx).
    + apply IHh3.
      intros x hx.
      simpl in hx.
      destruct hx as [hx | hx].
      * subst x.
        apply P_ass. simpl. left. reflexivity.
      * apply Prov_cons.
        exact (hD x hx).
  - apply P_allI.
    apply IHh.
    intros x hx.
    apply in_map_iff in hx.
    destruct hx as [x0 [hx hx0]].
    subst x.
    exact (Prov_rename De x0 (hD x0 hx0) S).
  - exact (P_allE De a t (IHh De hD)).
  - exact (P_exI De a t (IHh De hD)).
  - apply (P_exE De a c (IHh1 De hD)).
    apply IHh2.
    intros x hx.
    simpl in hx.
    destruct hx as [hx | hx].
    + subst x.
      apply P_ass. simpl. left. reflexivity.
    + apply in_map_iff in hx.
      destruct hx as [x0 [hx hx0]].
      subst x.
      apply Prov_cons.
      exact (Prov_rename De x0 (hD x0 hx0) S).
  - exact (P_eqRefl De t).
  - exact (P_eqElim De s t a (IHh1 De hD) (IHh2 De hD)).
Qed.

Lemma soundness : forall (M : Model) G a,
  Prov G a ->
  forall e : nat -> M, (forall x, In x G -> Sat M e x) -> Sat M e a.
Proof.
  intros M G a h.
  induction h; intros e hG; simpl.
  - exact (hG a H).
  - intros ha.
    apply IHh.
    intros x hx.
    simpl in hx.
    destruct hx as [hx | hx].
    + subst x. exact ha.
    + exact (hG x hx).
  - exact (IHh1 e hG (IHh2 e hG)).
  - exfalso. exact (IHh e hG).
  - destruct (classic (Sat M e a)) as [ha | hna].
    + left. exact ha.
    + right. exact hna.
  - split; [exact (IHh1 e hG) | exact (IHh2 e hG)].
  - exact (proj1 (IHh e hG)).
  - exact (proj2 (IHh e hG)).
  - left. exact (IHh e hG).
  - right. exact (IHh e hG).
  - destruct (IHh1 e hG) as [ha | hb].
    + apply IHh2.
      intros x hx.
      simpl in hx.
      destruct hx as [hx | hx].
      * subst x. exact ha.
      * exact (hG x hx).
    + apply IHh3.
      intros x hx.
      simpl in hx.
      destruct hx as [hx | hx].
      * subst x. exact hb.
      * exact (hG x hx).
  - intros d.
    apply IHh.
    intros x hx.
    apply in_map_iff in hx.
    destruct hx as [g [hg_eq hg]].
    subst x.
    apply (proj2 (Sat_rename_succ M g e d)).
    exact (hG g hg).
  - apply (proj2 (Sat_instTerm M a t e)).
    exact (IHh e hG (Term.eval M e t)).
  - exists (Term.eval M e t).
    apply (proj1 (Sat_instTerm M a t e)).
    exact (IHh e hG).
  - destruct (IHh1 e hG) as [d hd].
    pose proof (IHh2 (scons M d e)) as hc_shift.
    assert (hctx : forall x, In x (a :: map (rename S) G) ->
      Sat M (scons M d e) x).
    {
      intros x hx.
      simpl in hx.
      destruct hx as [hx | hx].
      - subst x. exact hd.
      - apply in_map_iff in hx.
        destruct hx as [g [hg_eq hg]].
        subst x.
        apply (proj2 (Sat_rename_succ M g e d)).
        exact (hG g hg).
    }
    apply (proj1 (Sat_rename_succ M c e d)).
    exact (hc_shift hctx).
  - reflexivity.
  - pose proof (IHh1 e hG) as heq.
    pose proof (proj1 (Sat_instTerm M a s e) (IHh2 e hG)) as hs.
    assert (henv : forall n,
      scons M (Term.eval M e s) e n =
        scons M (Term.eval M e t) e n).
    {
      intros [|n]; simpl.
      - exact heq.
      - reflexivity.
    }
    pose proof (proj1 (Sat_ext M a
      (scons M (Term.eval M e s) e)
      (scons M (Term.eval M e t) e) henv) hs) as ht.
    apply (proj2 (Sat_instTerm M a t e)).
    exact ht.
Qed.

Definition BProv (B : formula -> Prop) (G : list formula)
    (phi : formula) : Prop :=
  exists L, (forall x, In x L -> B x) /\ Prov (L ++ G) phi.

Lemma BProv_mono : forall (B : formula -> Prop) G G' phi,
  (forall x, In x G -> In x G') ->
  BProv B G phi -> BProv B G' phi.
Proof.
  intros B G G' phi hsub [L [hL hp]].
  exists L.
  split; [exact hL |].
  apply (Prov_weaken (L ++ G) phi hp).
  intros x hx.
  apply in_app_iff in hx.
  apply in_app_iff.
  destruct hx as [hx | hx].
  - left. exact hx.
  - right. exact (hsub x hx).
Qed.

Lemma BProv_ax : forall (B : formula -> Prop) G phi,
  B phi -> BProv B G phi.
Proof.
  intros B G phi hphi.
  exists [phi].
  split.
  - intros x hx.
    simpl in hx.
    destruct hx as [hx | hx]; [subst x; exact hphi | contradiction].
  - apply P_ass.
    simpl. left. reflexivity.
Qed.

Lemma BProv_of_Prov : forall (B : formula -> Prop) G phi,
  Prov G phi -> BProv B G phi.
Proof.
  intros B G phi h.
  exists [].
  split.
  - intros x hx. contradiction.
  - simpl. exact h.
Qed.

Lemma BProv_weaken_nil : forall (B : formula -> Prop) G phi,
  BProv B [] phi -> BProv B G phi.
Proof.
  intros B G phi h.
  apply (BProv_mono B [] G phi).
  - intros x hx. contradiction.
  - exact h.
Qed.

Lemma BProv_ass : forall (B : formula -> Prop) G phi,
  In phi G -> BProv B G phi.
Proof.
  intros B G phi hphi.
  apply BProv_of_Prov.
  exact (P_ass G phi hphi).
Qed.

Lemma BProv_rename_of_sentences : forall (B : formula -> Prop),
  Sentences B -> forall G phi,
  BProv B G phi -> forall r,
  BProv B (map (rename r) G) (rename r phi).
Proof.
  intros B hB G phi [L [hL hp]] r.
  exists L.
  split; [exact hL |].
  pose proof (Prov_rename (L ++ G) phi hp r) as hpRen.
  apply (Prov_weaken (map (rename r) (L ++ G)) (rename r phi) hpRen).
  intros x hx.
  rewrite map_app in hx.
  apply in_app_iff in hx.
  apply in_app_iff.
  destruct hx as [hx | hx].
  - left.
    apply in_map_iff in hx.
    destruct hx as [y [hy hyL]].
    subst x.
    rewrite (rename_eq_of_sentence y (hB y (hL y hyL)) r).
    exact hyL.
  - right. exact hx.
Qed.

Lemma BProv_subst_of_sentences : forall (B : formula -> Prop),
  Sentences B -> forall G phi,
  BProv B G phi -> forall sigma,
  BProv B (map (subst sigma) G) (subst sigma phi).
Proof.
  intros B hB G phi [L [hL hp]] sigma.
  exists L.
  split; [exact hL |].
  pose proof (Prov_subst (L ++ G) phi hp sigma) as hpSub.
  apply (Prov_weaken (map (subst sigma) (L ++ G)) (subst sigma phi) hpSub).
  intros x hx.
  rewrite map_app in hx.
  apply in_app_iff in hx.
  apply in_app_iff.
  destruct hx as [hx | hx].
  - left.
    apply in_map_iff in hx.
    destruct hx as [y [hy hyL]].
    subst x.
    rewrite (subst_eq_of_sentence y (hB y (hL y hyL)) sigma).
    exact hyL.
  - right. exact hx.
Qed.

Lemma BProv_mp : forall (B : formula -> Prop) G a b,
  BProv B G (pImp a b) -> BProv B G a -> BProv B G b.
Proof.
  intros B G a b [L1 [hL1 hpimp]] [L2 [hL2 hpa]].
  exists (L1 ++ L2).
  split.
  - intros x hx.
    apply in_app_iff in hx.
    destruct hx as [hx | hx].
    + exact (hL1 x hx).
    + exact (hL2 x hx).
  - apply (P_impE ((L1 ++ L2) ++ G) a b).
    + apply (Prov_weaken (L1 ++ G) (pImp a b) hpimp).
      intros x hx.
      apply in_app_iff in hx.
      apply in_app_iff.
      destruct hx as [hx | hx].
      * left. apply in_app_iff. left. exact hx.
      * right. exact hx.
    + apply (Prov_weaken (L2 ++ G) a hpa).
      intros x hx.
      apply in_app_iff in hx.
      apply in_app_iff.
      destruct hx as [hx | hx].
      * left. apply in_app_iff. right. exact hx.
      * right. exact hx.
Qed.

Lemma BProv_bound_list : forall (B : formula -> Prop) D L,
  (forall x, In x L -> BProv B D x) ->
  exists Lb, (forall x, In x Lb -> B x) /\
    forall x, In x L -> Prov (Lb ++ D) x.
Proof.
  intros B D L.
  induction L as [|a L IH]; intro hL.
  - exists [].
    split.
    + intros x hx. contradiction.
    + intros x hx. contradiction.
  - destruct (hL a (or_introl eq_refl)) as [La [hLa hpa]].
    destruct (IH (fun x hx => hL x (or_intror hx))) as
      [Lb [hLb hpL]].
    exists (La ++ Lb).
    split.
    + intros x hx.
      apply in_app_iff in hx.
      destruct hx as [hx | hx].
      * exact (hLa x hx).
      * exact (hLb x hx).
    + intros x hx.
      simpl in hx.
      destruct hx as [hx | hx].
      * subst x.
        apply (Prov_weaken (La ++ D) a hpa).
        intros y hy.
        apply in_app_iff in hy.
        apply in_app_iff.
        destruct hy as [hy | hy].
        -- left. apply in_app_iff. left. exact hy.
        -- right. exact hy.
      * apply (Prov_weaken (Lb ++ D) x (hpL x hx)).
        intros y hy.
        apply in_app_iff in hy.
        apply in_app_iff.
        destruct hy as [hy | hy].
        -- left. apply in_app_iff. right. exact hy.
        -- right. exact hy.
Qed.

Lemma BProv_lift : forall (B C : formula -> Prop) G D phi,
  BProv B G phi ->
  (forall b, B b -> BProv C D b) ->
  (forall g, In g G -> BProv C D g) ->
  BProv C D phi.
Proof.
  intros B C G D phi [Lb [hLb hp]] hB hG.
  assert (hctx : forall x, In x (Lb ++ G) -> BProv C D x).
  {
    intros x hx.
    apply in_app_iff in hx.
    destruct hx as [hx | hx].
    - exact (hB x (hLb x hx)).
    - exact (hG x hx).
  }
  destruct (BProv_bound_list C D (Lb ++ G) hctx) as
    [Lc [hLc hpctx]].
  exists Lc.
  split; [exact hLc |].
  exact (Prov_cut (Lb ++ G) phi hp (Lc ++ D) hpctx).
Qed.

Lemma BProv_cut : forall (B : formula -> Prop) G D phi,
  BProv B G phi ->
  (forall g, In g G -> BProv B D g) ->
  BProv B D phi.
Proof.
  intros B G D phi h hG.
  eapply BProv_lift.
  - exact h.
  - intros b hb.
    apply BProv_ax.
    exact hb.
  - exact hG.
Qed.

Lemma BProv_theory_mono : forall (B C : formula -> Prop) G phi,
  (forall b, B b -> C b) -> BProv B G phi -> BProv C G phi.
Proof.
  intros B C G phi hBC h.
  eapply BProv_lift.
  - exact h.
  - intros b hb.
    apply BProv_ax.
    exact (hBC b hb).
  - intros g hg.
    apply BProv_of_Prov.
    exact (P_ass G g hg).
Qed.

Ltac bprov_mem :=
  repeat rewrite in_app_iff in *; simpl in *; firstorder subst; auto.

Lemma BProv_eqElim : forall (B : formula -> Prop) G s t a,
  BProv B G (pEq s t) ->
  BProv B G (subst (instTerm s) a) ->
  BProv B G (subst (instTerm t) a).
Proof.
  intros B G s t a [Leq [hLeq hpeq]] [La [hLa hpa]].
  exists (Leq ++ La).
  split.
  - intros x hx. apply in_app_iff in hx.
    destruct hx as [hx | hx]; [apply hLeq | apply hLa]; exact hx.
  - apply (P_eqElim ((Leq ++ La) ++ G) s t a).
    + apply (Prov_weaken (Leq ++ G) (pEq s t) hpeq).
      intros x hx; bprov_mem.
    + apply (Prov_weaken (La ++ G) (subst (instTerm s) a) hpa).
      intros x hx; bprov_mem.
Qed.

Lemma BProv_eqRefl : forall (B : formula -> Prop) G t,
  BProv B G (pEq t t).
Proof.
  intros B G t.
  apply BProv_of_Prov.
  apply P_eqRefl.
Qed.

Lemma BProv_eqSym : forall (B : formula -> Prop) G s t,
  BProv B G (pEq s t) -> BProv B G (pEq t s).
Proof.
  intros B G s t heq.
  pose proof (BProv_eqRefl B G s) as hrefl.
  assert (ha : BProv B G
      (subst (instTerm s) (pEq (tVar 0) (Term.rename S s)))).
  {
    simpl.
    rewrite term_subst_instTerm_rename_succ.
    exact hrefl.
  }
  pose proof (BProv_eqElim B G s t
    (pEq (tVar 0) (Term.rename S s)) heq ha) as h.
  simpl in h.
  rewrite term_subst_instTerm_rename_succ in h.
  exact h.
Qed.

Lemma BProv_eqTrans : forall (B : formula -> Prop) G s t u,
  BProv B G (pEq s t) ->
  BProv B G (pEq t u) ->
  BProv B G (pEq s u).
Proof.
  intros B G s t u hst htu.
  assert (ha : BProv B G
      (subst (instTerm t) (pEq (Term.rename S s) (tVar 0)))).
  {
    simpl.
    rewrite term_subst_instTerm_rename_succ.
    exact hst.
  }
  pose proof (BProv_eqElim B G t u
    (pEq (Term.rename S s) (tVar 0)) htu ha) as h.
  simpl in h.
  rewrite term_subst_instTerm_rename_succ in h.
  exact h.
Qed.

Lemma BProv_eq_congr_term : forall (B : formula -> Prop) G s t c,
  BProv B G (pEq s t) ->
  BProv B G
    (pEq (Term.subst (instTerm s) c) (Term.subst (instTerm t) c)).
Proof.
  intros B G s t c heq.
  pose proof (BProv_eqRefl B G (Term.subst (instTerm s) c)) as hrefl.
  assert (ha : BProv B G
      (subst (instTerm s)
        (pEq (Term.rename S (Term.subst (instTerm s) c)) c))).
  {
    simpl.
    rewrite term_subst_instTerm_rename_succ.
    exact hrefl.
  }
  pose proof (BProv_eqElim B G s t
    (pEq (Term.rename S (Term.subst (instTerm s) c)) c) heq ha) as h.
  simpl in h.
  rewrite term_subst_instTerm_rename_succ in h.
  exact h.
Qed.

Lemma BProv_eq_congr_succ : forall (B : formula -> Prop) G s t,
  BProv B G (pEq s t) ->
  BProv B G (pEq (tSucc s) (tSucc t)).
Proof.
  intros B G s t heq.
  pose proof (BProv_eq_congr_term B G s t (tSucc (tVar 0)) heq) as h.
  simpl in h.
  exact h.
Qed.

Lemma BProv_eq_congr_add_left : forall (B : formula -> Prop) G s t u,
  BProv B G (pEq s t) ->
  BProv B G (pEq (tAdd s u) (tAdd t u)).
Proof.
  intros B G s t u heq.
  pose proof (BProv_eq_congr_term B G s t
    (tAdd (tVar 0) (Term.rename S u)) heq) as h.
  simpl in h.
  rewrite !term_subst_instTerm_rename_succ in h.
  exact h.
Qed.

Lemma BProv_eq_congr_add_right : forall (B : formula -> Prop) G u s t,
  BProv B G (pEq s t) ->
  BProv B G (pEq (tAdd u s) (tAdd u t)).
Proof.
  intros B G u s t heq.
  pose proof (BProv_eq_congr_term B G s t
    (tAdd (Term.rename S u) (tVar 0)) heq) as h.
  simpl in h.
  rewrite !term_subst_instTerm_rename_succ in h.
  exact h.
Qed.

Lemma BProv_eq_congr_add : forall (B : formula -> Prop) G s t u v,
  BProv B G (pEq s t) ->
  BProv B G (pEq u v) ->
  BProv B G (pEq (tAdd s u) (tAdd t v)).
Proof.
  intros B G s t u v hst huv.
  eapply BProv_eqTrans.
  - apply BProv_eq_congr_add_left.
    exact hst.
  - apply BProv_eq_congr_add_right.
    exact huv.
Qed.

Lemma BProv_eq_congr_mul_left : forall (B : formula -> Prop) G s t u,
  BProv B G (pEq s t) ->
  BProv B G (pEq (tMul s u) (tMul t u)).
Proof.
  intros B G s t u heq.
  pose proof (BProv_eq_congr_term B G s t
    (tMul (tVar 0) (Term.rename S u)) heq) as h.
  simpl in h.
  rewrite !term_subst_instTerm_rename_succ in h.
  exact h.
Qed.

Lemma BProv_eq_congr_mul_right : forall (B : formula -> Prop) G u s t,
  BProv B G (pEq s t) ->
  BProv B G (pEq (tMul u s) (tMul u t)).
Proof.
  intros B G u s t heq.
  pose proof (BProv_eq_congr_term B G s t
    (tMul (Term.rename S u) (tVar 0)) heq) as h.
  simpl in h.
  rewrite !term_subst_instTerm_rename_succ in h.
  exact h.
Qed.

Lemma BProv_eq_congr_mul : forall (B : formula -> Prop) G s t u v,
  BProv B G (pEq s t) ->
  BProv B G (pEq u v) ->
  BProv B G (pEq (tMul s u) (tMul t v)).
Proof.
  intros B G s t u v hst huv.
  eapply BProv_eqTrans.
  - apply BProv_eq_congr_mul_left.
    exact hst.
  - apply BProv_eq_congr_mul_right.
    exact huv.
Qed.

Lemma BProv_context_cons : forall (B : formula -> Prop) G a b,
  BProv B G b -> BProv B (a :: G) b.
Proof.
  intros B G a b h.
  apply (BProv_mono B G (a :: G) b).
  - intros x hx. right. exact hx.
  - exact h.
Qed.

(** A derivation remains valid after prepending any finite block of local
    assumptions.  Keeping this next to [BProv_context_cons] makes the generic
    transport available throughout the foundational PA/HF development. *)
Lemma BProv_context_prefix : forall
    (B : formula -> Prop) prefix G phi,
  BProv B G phi ->
  BProv B (prefix ++ G) phi.
Proof.
  intros B prefix G phi hphi.
  induction prefix as [|head tail ih].
  - exact hphi.
  - exact (BProv_context_cons B (tail ++ G) head phi ih).
Qed.

(** Inference-friendly specialization for the frequent two-assumption case. *)
Lemma BProv_context_two : forall
    (B : formula -> Prop) G first second phi,
  BProv B G phi ->
  BProv B (first :: second :: G) phi.
Proof.
  intros B G first second phi hphi.
  exact (BProv_context_prefix B [first; second] G phi hphi).
Qed.

(** Inference-friendly specialization for three opened assumptions. *)
Lemma BProv_context_three : forall
    (B : formula -> Prop) G first second third phi,
  BProv B G phi ->
  BProv B (first :: second :: third :: G) phi.
Proof.
  intros B G first second third phi hphi.
  exact (BProv_context_prefix B [first; second; third] G phi hphi).
Qed.

Lemma BProv_impI : forall (B : formula -> Prop) G a b,
  BProv B (a :: G) b -> BProv B G (pImp a b).
Proof.
  intros B G a b [L [hL hp]].
  exists L. split; [exact hL |].
  apply P_impI.
  apply (Prov_weaken (L ++ a :: G) b hp).
  intros x hx.
  apply in_app_iff in hx.
  simpl in hx.
  simpl.
  destruct hx as [hx | [hx | hx]].
  - right. apply in_app_iff. left. exact hx.
  - left. exact hx.
  - right. apply in_app_iff. right. exact hx.
Qed.

Lemma BProv_impI_after_prefix : forall (B : formula -> Prop) Gamma Delta a b,
  BProv B (Gamma ++ a :: Delta) b ->
  BProv B (Gamma ++ Delta) (pImp a b).
Proof.
  intros B Gamma Delta a b [L [hL hp]].
  exists L. split; [exact hL |].
  apply P_impI.
  apply (Prov_weaken (L ++ Gamma ++ a :: Delta) b hp).
  intros x hx.
  apply in_app_iff in hx.
  simpl.
  destruct hx as [hx | hx].
  - right. apply in_app_iff. left. exact hx.
  - apply in_app_iff in hx.
    destruct hx as [hx | hx].
    + right. apply in_app_iff. right. apply in_app_iff. left. exact hx.
    + simpl in hx.
      destruct hx as [hx | hx].
      * left. exact hx.
      * right. apply in_app_iff. right. apply in_app_iff. right. exact hx.
Qed.

Lemma BProv_andI : forall (B : formula -> Prop) G a b,
  BProv B G a -> BProv B G b -> BProv B G (pAnd a b).
Proof.
  intros B G a b [La [hLa hpa]] [Lb [hLb hpb]].
  exists (La ++ Lb). split.
  - intros x hx. apply in_app_iff in hx.
    destruct hx as [hx | hx]; [apply hLa | apply hLb]; exact hx.
  - apply P_andI.
    + apply (Prov_weaken (La ++ G) a hpa).
      intros x hx; bprov_mem.
    + apply (Prov_weaken (Lb ++ G) b hpb).
      intros x hx; bprov_mem.
Qed.

Lemma BProv_botE : forall (B : formula -> Prop) G a,
  BProv B G pBot -> BProv B G a.
Proof.
  intros B G a [L [hL hp]].
  exists L. split; [exact hL |].
  exact (P_botE (L ++ G) a hp).
Qed.

Lemma BProv_andE1 : forall (B : formula -> Prop) G a b,
  BProv B G (pAnd a b) -> BProv B G a.
Proof.
  intros B G a b [L [hL hp]].
  exists L. split; [exact hL |].
  exact (P_andE1 (L ++ G) a b hp).
Qed.

Lemma BProv_andE2 : forall (B : formula -> Prop) G a b,
  BProv B G (pAnd a b) -> BProv B G b.
Proof.
  intros B G a b [L [hL hp]].
  exists L. split; [exact hL |].
  exact (P_andE2 (L ++ G) a b hp).
Qed.

Lemma BProv_orI1 : forall (B : formula -> Prop) G a b,
  BProv B G a -> BProv B G (pOr a b).
Proof.
  intros B G a b [L [hL hp]].
  exists L. split; [exact hL |].
  exact (P_orI1 (L ++ G) a b hp).
Qed.

Lemma BProv_orI2 : forall (B : formula -> Prop) G a b,
  BProv B G b -> BProv B G (pOr a b).
Proof.
  intros B G a b [L [hL hp]].
  exists L. split; [exact hL |].
  exact (P_orI2 (L ++ G) a b hp).
Qed.

Lemma BProv_orE : forall (B : formula -> Prop) G a b c,
  BProv B G (pOr a b) ->
  BProv B (a :: G) c ->
  BProv B (b :: G) c ->
  BProv B G c.
Proof.
  intros B G a b c [Lo [hLo hpo]] [La [hLa hpa]] [Lb [hLb hpb]].
  exists (Lo ++ La ++ Lb). split.
  - intros x hx.
    apply in_app_iff in hx.
    destruct hx as [hx | hx].
    + apply hLo. exact hx.
    + apply in_app_iff in hx.
      destruct hx as [hx | hx].
      * apply hLa. exact hx.
      * apply hLb. exact hx.
  - apply (P_orE ((Lo ++ La ++ Lb) ++ G) a b c).
    + apply (Prov_weaken (Lo ++ G) (pOr a b) hpo).
      intros x hx.
      apply in_app_iff in hx.
      apply in_app_iff.
      destruct hx as [hx | hx].
      * left. apply in_app_iff. left. exact hx.
      * right. exact hx.
    + apply (Prov_weaken (La ++ a :: G) c hpa).
      intros x hx.
      apply in_app_iff in hx.
      simpl in hx.
      simpl.
      destruct hx as [hx | [hx | hx]].
      * right. apply in_app_iff. left. apply in_app_iff. right.
        apply in_app_iff. left. exact hx.
      * left. exact hx.
      * right. apply in_app_iff. right. exact hx.
    + apply (Prov_weaken (Lb ++ b :: G) c hpb).
      intros x hx.
      apply in_app_iff in hx.
      simpl in hx.
      simpl.
      destruct hx as [hx | [hx | hx]].
      * right. apply in_app_iff. left. apply in_app_iff. right.
        apply in_app_iff. right. exact hx.
      * left. exact hx.
      * right. apply in_app_iff. right. exact hx.
Qed.

Lemma BProv_allE : forall (B : formula -> Prop) G a t,
  BProv B G (pAll a) -> BProv B G (subst (instTerm t) a).
Proof.
  intros B G a t [L [hL hp]].
  exists L. split; [exact hL |].
  exact (P_allE (L ++ G) a t hp).
Qed.

Lemma BProv_exI : forall (B : formula -> Prop) G a t,
  BProv B G (subst (instTerm t) a) -> BProv B G (pEx a).
Proof.
  intros B G a t [L [hL hp]].
  exists L. split; [exact hL |].
  exact (P_exI (L ++ G) a t hp).
Qed.

Lemma map_rename_S_eq_of_sentences : forall (B : formula -> Prop) L,
  Sentences B ->
  (forall x, In x L -> B x) ->
  map (rename S) L = L.
Proof.
  induction L as [|x xs IH]; intros hB hL; simpl.
  - reflexivity.
  - rewrite (rename_eq_of_sentence x).
    + rewrite (IH hB (fun y hy => hL y (or_intror hy))).
      reflexivity.
    + apply hB.
      apply hL. simpl. left. reflexivity.
Qed.

Lemma BProv_allI_of_sentences : forall (B : formula -> Prop) G a,
  Sentences B ->
  BProv B (map (rename S) G) a ->
  BProv B G (pAll a).
Proof.
  intros B G a hB [L [hL hp]].
  pose proof (map_rename_S_eq_of_sentences B L hB hL) as hLmap.
  exists L. split; [exact hL |].
  apply P_allI.
  apply (Prov_weaken (L ++ map (rename S) G) a hp).
  intros x hx.
  rewrite map_app.
  rewrite hLmap.
  exact hx.
Qed.

Lemma BProv_exE_of_sentences : forall (B : formula -> Prop) G a c,
  Sentences B ->
  BProv B G (pEx a) ->
  BProv B (a :: map (rename S) G) (rename S c) ->
  BProv B G c.
Proof.
  intros B G a c hB [Le [hLe hpe]] [Lb [hLb hpb]].
  pose proof (map_rename_S_eq_of_sentences B Lb hB hLb) as hLbmap.
  exists (Le ++ Lb). split.
  - intros x hx.
    apply in_app_iff in hx.
    destruct hx as [hx | hx].
    + exact (hLe x hx).
    + exact (hLb x hx).
  - apply (P_exE ((Le ++ Lb) ++ G) a c).
    + apply (Prov_weaken (Le ++ G) (pEx a) hpe).
      intros x hx.
      apply in_app_iff in hx.
      apply in_app_iff.
      destruct hx as [hx | hx].
      * left. apply in_app_iff. left. exact hx.
      * right. exact hx.
    + apply (Prov_weaken (Lb ++ a :: map (rename S) G) (rename S c) hpb).
      intros x hx.
      apply in_app_iff in hx.
      simpl in hx.
      simpl.
      destruct hx as [hx | [hx | hx]].
      * right.
        rewrite map_app.
        apply in_app_iff. left.
        rewrite map_app.
        apply in_app_iff. right.
        rewrite hLbmap.
        exact hx.
      * left. exact hx.
      * right.
        rewrite map_app.
        apply in_app_iff. right.
        exact hx.
Qed.


(* Lean: BProv_rename_succ_context_cons_of_sentences *)
Lemma BProv_rename_succ_context_cons_of_sentences :
  forall (B : formula -> Prop),
  Sentences B ->
  forall G a b,
  BProv B G b ->
  BProv B (a :: map (rename S) G) (rename S b).
Proof.
  intros B hB G a b h.
  apply BProv_context_cons.
  apply (BProv_rename_of_sentences B hB G b h S).
Qed.

(* Lean: BProv_closeN_nil_of_sentences *)
Lemma BProv_closeN_nil_of_sentences :
  forall (B : formula -> Prop),
  Sentences B ->
  forall n phi,
  BProv B nil phi ->
  BProv B nil (closeN n phi).
Proof.
  intros B hB n.
  induction n as [|n IH]; intros phi h.
  - exact h.
  - simpl.
    apply IH.
    apply (BProv_allI_of_sentences B nil phi hB).
    exact h.
Qed.

Lemma BProv_closeN_allE_rename : forall (B : formula -> Prop) G k phi r,
  (forall n, Free n phi -> n < k) ->
  BProv B G (closeN k phi) ->
  BProv B G (rename r phi).
Proof.
  intros B G k.
  induction k as [|k IH]; intros phi r hfree h.
  - assert (hsent : Sentence phi).
    {
      intros n hn.
      pose proof (hfree n hn) as hlt.
      lia.
    }
    rewrite (rename_eq_of_sentence phi hsent r).
    exact h.
  - set (tail := fun n => r (S n)).
    assert (hclosed : BProv B G (rename tail (pAll phi))).
    {
      apply (IH (pAll phi) tail).
      - intros n hn.
        simpl in hn.
        pose proof (hfree (S n) hn) as hlt.
        lia.
      - simpl in h.
        exact h.
    }
    change (BProv B G (pAll (rename (up tail) phi))) in hclosed.
    pose proof (BProv_allE B G (rename (up tail) phi)
      (tVar (r 0)) hclosed) as hinst.
    rewrite subst_instTerm_var in hinst.
    rewrite rename_comp in hinst.
    replace (rename (fun n : nat => inst (r 0) (up tail n)) phi)
      with (rename r phi) in hinst.
    + exact hinst.
    + apply rename_ext.
      intros [|n]; unfold tail; reflexivity.
Qed.

Lemma BProv_sealPA_allE_rename : forall (B : formula -> Prop) G phi r,
  BProv B G (sealPA phi) ->
  BProv B G (rename r phi).
Proof.
  intros B G phi r h.
  unfold sealPA in h.
  apply (BProv_closeN_allE_rename B G (bound phi) phi r).
  - intros n hn.
    apply free_lt_bound.
    exact hn.
  - exact h.
Qed.

Lemma soundness_BProv : forall (M : Model) (B : formula -> Prop) G phi,
  BProv B G phi ->
  forall e : nat -> M,
  (forall b, B b -> Sat M e b) ->
  (forall g, In g G -> Sat M e g) ->
  Sat M e phi.
Proof.
  intros M B G phi [L [hL hp]] e hB hG.
  apply (soundness M (L ++ G) phi hp e).
  intros x hx.
  apply in_app_iff in hx.
  destruct hx as [hx | hx].
  - exact (hB x (hL x hx)).
  - exact (hG x hx).
Qed.

Definition substZero : nat -> term :=
  fun n =>
    match n with
    | 0 => tZero
    | S k => tVar k
    end.

Definition substZeroAt (p : nat) : nat -> term :=
  fun n =>
    if n <? p then tVar n
    else if n =? p then tZero
    else tVar (n - 1).

Lemma substZeroAt_lt : forall p n,
  n < p -> substZeroAt p n = tVar n.
Proof.
  intros p n h.
  unfold substZeroAt.
  destruct (Nat.ltb_spec n p); [reflexivity | lia].
Qed.

Lemma substZeroAt_eq : forall p,
  substZeroAt p p = tZero.
Proof.
  intro p.
  unfold substZeroAt.
  destruct (Nat.ltb_spec p p); [lia |].
  destruct (Nat.eqb_spec p p); [reflexivity | congruence].
Qed.

Lemma substZeroAt_gt : forall p n,
  p < n -> substZeroAt p n = tVar (n - 1).
Proof.
  intros p n h.
  unfold substZeroAt.
  destruct (Nat.ltb_spec n p); [lia |].
  destruct (Nat.eqb_spec n p); [lia | reflexivity].
Qed.

Lemma substZeroAt_zero :
  substZeroAt 0 = substZero.
Proof.
  apply functional_extensionality.
  intros [|n].
  - apply substZeroAt_eq.
  - unfold substZero.
    rewrite substZeroAt_gt; [|lia].
    f_equal.
    lia.
Qed.

Lemma upSubst_substZeroAt : forall p,
  Term.upSubst (substZeroAt p) = substZeroAt (S p).
Proof.
  intro p.
  apply functional_extensionality.
  intros [|n].
  - reflexivity.
  - simpl.
    destruct (lt_eq_lt_dec n p) as [[hlt | heq] | hgt].
    + rewrite (substZeroAt_lt p n hlt).
      rewrite (substZeroAt_lt (S p) (S n)); [reflexivity | lia].
    + subst n.
      rewrite substZeroAt_eq.
      rewrite substZeroAt_eq.
      reflexivity.
    + rewrite (substZeroAt_gt p n hgt).
      rewrite (substZeroAt_gt (S p) (S n)); [|lia].
      simpl.
      f_equal.
      lia.
Qed.

Definition substSuccVar : nat -> term :=
  fun n =>
    match n with
    | 0 => tSucc (tVar 0)
    | S k => tVar (S k)
    end.

Lemma term_substZero_rename_succ : forall t,
  Term.subst substZero (Term.rename S t) = t.
Proof.
  induction t; simpl; try reflexivity.
  - now rewrite IHt.
  - now rewrite IHt1, IHt2.
  - now rewrite IHt1, IHt2.
Qed.

Lemma term_substSuccVar_rename_succ : forall t,
  Term.subst substSuccVar (Term.rename S t) = Term.rename S t.
Proof.
  induction t; simpl; try reflexivity.
  - now rewrite IHt.
  - now rewrite IHt1, IHt2.
  - now rewrite IHt1, IHt2.
Qed.

(* Lean: term_subst_up_up_up_substZero_rename_four_succ *)
Lemma term_subst_up_up_up_substZero_rename_four_succ : forall t,
  Term.subst
      (Term.upSubst (Term.upSubst (Term.upSubst substZero)))
      (Term.rename (fun n => n + 1 + 1 + 1 + 1) t) =
    Term.rename (fun n => n + 1 + 1 + 1) t.
Proof.
  intro t.
  assert (hzero : substZero = instTerm tZero).
  {
    apply functional_extensionality.
    intros [|n]; reflexivity.
  }
  rewrite hzero.
  replace (Term.rename (fun n => n + 1 + 1 + 1 + 1) t)
    with (Term.rename (fun n => S (S (S (S n)))) t)
    by (apply Term.rename_ext; intro n; lia).
  replace (Term.rename (fun n => n + 1 + 1 + 1) t)
    with (Term.rename (fun n => S (S (S n))) t)
    by (apply Term.rename_ext; intro n; lia).
  exact (term_subst_up_up_up_instTerm_rename_four_succ t tZero).
Qed.

(* Lean: term_subst_up_substZero_rename_two_succ *)
Lemma term_subst_up_substZero_rename_two_succ : forall t,
  Term.subst (Term.upSubst substZero)
      (Term.rename (fun n => n + 1 + 1) t) =
    Term.rename S t.
Proof.
  intro t.
  assert (hzero : substZero = instTerm tZero).
  {
    apply functional_extensionality.
    intros [|n]; reflexivity.
  }
  rewrite hzero.
  replace (Term.rename (fun n => n + 1 + 1) t)
    with (Term.rename (fun n => S (S n)) t)
    by (apply Term.rename_ext; intro n; lia).
  exact (term_subst_upSubst_instTerm_rename_two_succ t tZero).
Qed.

(* Lean: term_subst_up_substSuccVar_rename_two_succ *)
Lemma term_subst_up_substSuccVar_rename_two_succ : forall t,
  Term.subst (Term.upSubst substSuccVar)
      (Term.rename (fun n => n + 1 + 1) t) =
    Term.rename (fun n => n + 1 + 1) t.
Proof.
  intro t.
  replace (Term.rename (fun n => n + 1 + 1) t)
    with (Term.rename S (Term.rename S t))
    by (rewrite Term.rename_comp; apply Term.rename_ext; intro n; lia).
  rewrite Term.subst_rename_succ_up.
  rewrite term_substSuccVar_rename_succ.
  reflexivity.
Qed.

(* Lean: term_subst_up_up_up_substSuccVar_rename_four_succ *)
Lemma term_subst_up_up_up_substSuccVar_rename_four_succ : forall t,
  Term.subst
      (Term.upSubst (Term.upSubst (Term.upSubst substSuccVar)))
      (Term.rename (fun n => n + 1 + 1 + 1 + 1) t) =
    Term.rename (fun n => n + 1 + 1 + 1 + 1) t.
Proof.
  intro t.
  replace (Term.rename (fun n => n + 1 + 1 + 1 + 1) t)
    with (Term.rename S
      (Term.rename S (Term.rename S (Term.rename S t))))
    by (repeat rewrite Term.rename_comp;
        apply Term.rename_ext; intro n; lia).
  repeat rewrite Term.subst_rename_succ_up.
  rewrite term_substSuccVar_rename_succ.
  reflexivity.
Qed.

Definition substSuccAt (p : nat) : nat -> term :=
  fun n => if n =? p then tSucc (tVar p) else tVar n.

Lemma substSuccAt_eq : forall p,
  substSuccAt p p = tSucc (tVar p).
Proof.
  intro p.
  unfold substSuccAt.
  destruct (Nat.eqb_spec p p); [reflexivity | congruence].
Qed.

Lemma substSuccAt_ne : forall p n,
  n <> p -> substSuccAt p n = tVar n.
Proof.
  intros p n h.
  unfold substSuccAt.
  destruct (Nat.eqb_spec n p); [congruence | reflexivity].
Qed.

Lemma substSuccAt_zero :
  substSuccAt 0 = substSuccVar.
Proof.
  apply functional_extensionality.
  intros [|n].
  - apply substSuccAt_eq.
  - apply substSuccAt_ne. lia.
Qed.

Lemma upSubst_substSuccAt : forall p,
  Term.upSubst (substSuccAt p) = substSuccAt (S p).
Proof.
  intro p.
  apply functional_extensionality.
  intros [|n].
  - reflexivity.
  - simpl.
    destruct (Nat.eq_dec n p) as [heq | hne].
    + subst n.
      rewrite substSuccAt_eq.
      rewrite substSuccAt_eq.
      reflexivity.
    + rewrite (substSuccAt_ne p n hne).
      rewrite (substSuccAt_ne (S p) (S n)); [reflexivity | lia].
Qed.

Definition succInj : formula :=
  pAll (pAll (pImp
    (pEq (tSucc (tVar 1)) (tSucc (tVar 0)))
    (pEq (tVar 1) (tVar 0)))).

Definition zeroNotSucc : formula :=
  pAll (pImp (pEq (tSucc (tVar 0)) tZero) pBot).

Definition addZero : formula :=
  pAll (pEq (tAdd (tVar 0) tZero) (tVar 0)).

Definition addSucc : formula :=
  pAll (pAll (pEq
    (tAdd (tVar 1) (tSucc (tVar 0)))
    (tSucc (tAdd (tVar 1) (tVar 0))))).

Definition mulZero : formula :=
  pAll (pEq (tMul (tVar 0) tZero) tZero).

Definition mulSucc : formula :=
  pAll (pAll (pEq
    (tMul (tVar 1) (tSucc (tVar 0)))
    (tAdd (tMul (tVar 1) (tVar 0)) (tVar 1)))).

Definition inductionForm (phi : formula) : formula :=
  pImp
    (pAnd (subst substZero phi)
      (pAll (pImp phi (subst substSuccVar phi))))
    (pAll phi).

Lemma BProv_inductionForm_mp : forall (B : formula -> Prop) G phi,
  BProv B G (inductionForm phi) ->
  BProv B G (subst substZero phi) ->
  BProv B G (pAll (pImp phi (subst substSuccVar phi))) ->
  BProv B G (pAll phi).
Proof.
  intros B G phi hind hzero hsucc.
  unfold inductionForm in hind.
  exact (BProv_mp B G
    (pAnd (subst substZero phi)
      (pAll (pImp phi (subst substSuccVar phi))))
    (pAll phi) hind
    (BProv_andI B G (subst substZero phi)
      (pAll (pImp phi (subst substSuccVar phi))) hzero hsucc)).
Qed.

Definition Ax (f : formula) : Prop :=
  f = succInj \/ f = zeroNotSucc \/
  f = addZero \/ f = addSucc \/
  f = mulZero \/ f = mulSucc \/
  exists phi, f = inductionForm phi.

Definition Ax_s (f : formula) : Prop :=
  f = sealPA succInj \/ f = sealPA zeroNotSucc \/
  f = sealPA addZero \/ f = sealPA addSucc \/
  f = sealPA mulZero \/ f = sealPA mulSucc \/
  exists phi, f = sealPA (inductionForm phi).

Lemma sentence_ax_s : forall f, Ax_s f -> Sentence f.
Proof.
  intros f hf.
  unfold Ax_s in hf.
  destruct hf as [hf | [hf | [hf | [hf | [hf | [hf | [phi hf]]]]]]];
    subst f; apply sealPA_sentence.
Qed.

Lemma Ax_s_succInj : Ax_s (sealPA succInj).
Proof.
  unfold Ax_s. now left.
Qed.

Lemma Ax_s_zeroNotSucc : Ax_s (sealPA zeroNotSucc).
Proof.
  unfold Ax_s. right. now left.
Qed.

Lemma Ax_s_addZero : Ax_s (sealPA addZero).
Proof.
  unfold Ax_s. right. right. now left.
Qed.

Lemma Ax_s_addSucc : Ax_s (sealPA addSucc).
Proof.
  unfold Ax_s. right. right. right. now left.
Qed.

Lemma Ax_s_mulZero : Ax_s (sealPA mulZero).
Proof.
  unfold Ax_s. right. right. right. right. now left.
Qed.

Lemma Ax_s_mulSucc : Ax_s (sealPA mulSucc).
Proof.
  unfold Ax_s. right. right. right. right. right. now left.
Qed.

Lemma Ax_s_induction : forall phi, Ax_s (sealPA (inductionForm phi)).
Proof.
  intro phi.
  unfold Ax_s.
  right. right. right. right. right. right.
  exists phi. reflexivity.
Qed.

Lemma BProv_Ax_s_of_sealPA_rename : forall phi,
  Ax_s (sealPA phi) ->
  forall r, BProv Ax_s [] (rename r phi).
Proof.
  intros phi hphi r.
  apply (BProv_sealPA_allE_rename Ax_s [] phi r).
  apply BProv_ax.
  exact hphi.
Qed.

