    }
    assert (hright : BProv Ax_s [phi]
        (pEq (tSucc (tSucc (tAdd (Term.rename S x) (tVar 0))))
          (tSucc (tAdd (Term.rename S x) (tSucc (tVar 0)))))).
    {
      apply BProv_eq_congr_succ.
      exact (BProv_eqSym _ _ _ _ hrightStep).
    }
    unfold phi.
    simpl.
