          (leTermAt (tVar 1) tZero) (ltTermAt tZero (tVar 1)) hlt).
      }
      exact (BProv_exE_of_sentences Ax_s [pEx succBody] succBody
        (pOr (leTermAt (tVar 0) tZero) (ltTermAt tZero (tVar 0)))
        sentence_ax_s
        (BProv_ass Ax_s [pEx succBody] (pEx succBody)
