(* Lean: BProv_Ax_s_dvdAt_of_remAt_eqConst_zero *)
Lemma BProv_Ax_s_dvdAt_of_remAt_eqConst_zero :
  forall G rem value modulus,
  BProv Ax_s G (remAt rem value modulus) ->
