  assert (hbody : BProv Ax_s G
      (subst (instTerm modulus)
        (pAnd
          (pEq (tVar 0)
            (Term.rename S (betaModTermTerm step idx)))
          (remTermTermAt (Term.rename S out)
            (Term.rename S code) (tVar 0))))).
