      (tMul (tSucc (tVar idx)) (tVar step))
      (Term.numeral ((i + 1) * s)) hmulComputed).
  }
  unfold betaModTerm.
  replace (BetaModulus s i) with (S ((i + 1) * s))
    by (unfold BetaModulus; lia).
  simpl.
  exact hsucc.
Qed.

Lemma BProv_Ax_s_betaModTerm_constIdx_of_eqConst :
  forall G step s i,
