  BProv Ax_s G (eqConstAt idx i) ->
  BetaEntry c s (i + 1) o ->
  BProv Ax_s G
    (subst (instTerm (Term.numeral o))
      (betaAtSuccIdx 0 (S code) (S step) (S idx))).
Proof.
  intros G code step idx o c s i hcode hstep hidx hentry.
  destruct hentry as [q [hval hlt]].
