(* Lean: BProv_Ax_s_betaModTerm_modEq_zero_bot *)
Lemma BProv_Ax_s_betaModTerm_modEq_zero_bot :
  forall G modulus step idx pred,
  BProv Ax_s G (pEq (tVar modulus) (betaModTerm step idx)) ->
