  Term.rename (up (up (up (up S))))
      (Term.rename S (Term.rename S (Term.rename S (Term.rename S t)))) =
    Term.rename S
      (Term.rename S (Term.rename S (Term.rename S (Term.rename S t)))).
Proof.
  intro t.
