            D (tVar 0) (tVar (oldCode + 2)) (tVar (oldStep + 2))
            (tSucc (tVar 1)) hold hstepD).
        }
        assert (hnewStep : BProv Ax_s D
            (pEq (Term.rename (fun n => n + 2) tZero) tZero)).
        { simpl. apply BProv_eqRefl. }
        assert (hzeroBeta : BProv Ax_s D
