      (subst (Term.upSubst (instTerm (Term.numeral step)))
        (subst (Term.upSubst (Term.upSubst
          (instTerm (Term.numeral code))))
          (betaDiv2BitAt 0 2 1 (S (S (S elem))))))) ->
