  unfold crtInverseExistsTermAt. simpl.
  split.
  - intros [inverse [quotient hcert]].
    exists inverse, quotient.
    pose proof (proj1 (crtInverseTermAt_nat
      (scons nat quotient (scons nat inverse e))
