      (Term.rename (fun n => n + 2) modulus)
      (tVar 1) (tVar 0)) hcert) as hspec.
    repeat rewrite Term.eval_rename in hspec.
    simpl in hspec.
    replace
      (fun n => scons nat quotient (scons nat inverse e) (n + 2))
      with e in hspec.
