      (betaModTermTerm (Term.rename S step) (tVar 0))
      (Term.rename S product))).
    repeat rewrite Term.eval_rename.
    rewrite betaModTermTerm_nat.
    repeat rewrite Term.eval_rename.
    simpl.
    pose proof (h i hi) as hdiv.
    unfold BetaModulus in hdiv.
    replace
