    exists q.
    split; simpl in *; assumption.
  - intros [q [hval hlt]].
    exists (S (e idx)).
    split.
    + reflexivity.
    + apply (proj2 (betaAt_nat (scons nat (S (e idx)) e)
        (S out) (S code) (S step) 0)).
