Qed.

Lemma betaDiv2StepsThroughConstAt_nat :
    forall (e : nat -> nat) code step last,
  Sat natModel e (betaDiv2StepsThroughConstAt code step last) <->
    forall k, k <= last ->
      exists cur next bit,
        BetaEntry (e code) (e step) k cur /\
        BetaEntry (e code) (e step) (S k) next /\
        (bit = 0 \/ bit = 1) /\ cur = next + next + bit.
Proof.
  intros e code step last.
  unfold betaDiv2StepsThroughConstAt. simpl.
  split.
  - intros h k hk.
    assert (hkSat : Sat natModel (scons nat k e) (leConstAt 0 last)).
    {
      apply (proj2 (leConstAt_nat (scons nat k e) 0 last)).
      simpl. exact hk.
    }
    pose proof (proj1 (betaDiv2StepWitnessAt_nat
      (scons nat k e) (S code) (S step) 0) (h k hkSat)) as hw.
    simpl in hw. exact hw.
  - intros h k hkSat.
    assert (hk : k <= last).
    {
      pose proof (proj1 (leConstAt_nat (scons nat k e) 0 last) hkSat)
        as hle.
      simpl in hle. exact hle.
    }
    apply (proj2 (betaDiv2StepWitnessAt_nat
      (scons nat k e) (S code) (S step) 0)).
    simpl. exact (h k hk).
Qed.

Lemma betaDiv2BitAt_nat : forall (e : nat -> nat) bit code step idx,
  Sat natModel e (betaDiv2BitAt bit code step idx) <->
    BetaDiv2Bit (e code) (e step) (e idx) (e bit).
Proof.
  intros e bit code step idx.
  unfold betaDiv2BitAt, BetaDiv2Bit. simpl.
  split.
  - intros [cur [next [hcur [hnext hstep]]]].
    pose proof (proj1 (betaAt_nat_entry
      (scons nat next (scons nat cur e))
      1 (S (S code)) (S (S step)) (S (S idx))) hcur) as hcur'.
    pose proof (proj1 (betaAtSuccIdx_nat_entry
      (scons nat next (scons nat cur e))
      0 (S (S code)) (S (S step)) (S (S idx))) hnext) as hnext'.
    pose proof (proj1 (div2StepAt_nat
      (scons nat next (scons nat cur e)) 1 0 (S (S bit))) hstep)
      as hstep'.
    simpl in hcur', hnext', hstep'.
    destruct hstep' as [hbit hval].
    exists cur, next.
    unfold BetaDiv2Step.
    repeat split; assumption.
  - intros [cur [next [hcur [hnext [hbit hval]]]]].
    exists cur, next.
    split.
    + apply (proj2 (betaAt_nat_entry
        (scons nat next (scons nat cur e))
        1 (S (S code)) (S (S step)) (S (S idx)))).
      simpl. exact hcur.
    + split.
      * apply (proj2 (betaAtSuccIdx_nat_entry
          (scons nat next (scons nat cur e))
          0 (S (S code)) (S (S step)) (S (S idx)))).
        simpl. exact hnext.
      * apply (proj2 (div2StepAt_nat
          (scons nat next (scons nat cur e)) 1 0 (S (S bit)))).
        simpl. split; assumption.
Qed.

(* Lean: betaDiv2BitTermAt_nat *)
Lemma betaDiv2BitTermAt_nat : forall (e : nat -> nat) bit code step idx,
  Sat natModel e (betaDiv2BitTermAt bit code step idx) <->
    BetaDiv2Bit
      (Term.eval natModel e code)
      (Term.eval natModel e step)
      (Term.eval natModel e idx)
      (Term.eval natModel e bit).
Proof.
  intros e bit code step idx.
  unfold betaDiv2BitTermAt, BetaDiv2Bit. simpl.
  split.
  - intros [cur [next [hcur [hnext hstep]]]].
    pose proof (proj1 (betaTermTermAt_nat_entry
      (scons nat next (scons nat cur e))
      (tVar 1)
      (Term.rename (fun n : nat => n + 2) code)
      (Term.rename (fun n : nat => n + 2) step)
      (Term.rename (fun n : nat => n + 2) idx)) hcur) as hcur'.
    pose proof (proj1 (betaTermTermAt_nat_entry
      (scons nat next (scons nat cur e))
      (tVar 0)
      (Term.rename (fun n : nat => n + 2) code)
      (Term.rename (fun n : nat => n + 2) step)
      (tSucc (Term.rename (fun n : nat => n + 2) idx))) hnext)
      as hnext'.
    pose proof (proj1 (div2StepTermAt_nat
      (scons nat next (scons nat cur e))
      (tVar 1) (tVar 0)
      (Term.rename (fun n : nat => n + 2) bit)) hstep) as hstep'.
    assert (heval2 : forall t,
      Term.eval natModel (scons nat next (scons nat cur e))
        (Term.rename (fun n : nat => n + 2) t) =
      Term.eval natModel e t).
    {
      intro t.
      rewrite Term.eval_rename.
      apply Term.eval_ext.
      intro n.
      unfold scons.
      replace (n + 2) with (S (S n)) by lia.
      reflexivity.
    }
    simpl in hcur', hnext', hstep'.
    repeat rewrite heval2 in hcur'.
    repeat rewrite heval2 in hnext'.
    repeat rewrite heval2 in hstep'.
    destruct hstep' as [hbit hvalue].
    exists cur, next.
    unfold BetaDiv2Step.
    repeat split; assumption.
  - intros [cur [next [hcur [hnext [hbit hvalue]]]]].
    assert (heval2 : forall t,
      Term.eval natModel (scons nat next (scons nat cur e))
        (Term.rename (fun n : nat => n + 2) t) =
      Term.eval natModel e t).
    {
      intro t.
      rewrite Term.eval_rename.
      apply Term.eval_ext.
      intro n.
      unfold scons.
      replace (n + 2) with (S (S n)) by lia.
      reflexivity.
    }
    exists cur, next.
    split.
    + apply (proj2 (betaTermTermAt_nat_entry
      (scons nat next (scons nat cur e))
      (tVar 1)
      (Term.rename (fun n : nat => n + 2) code)
      (Term.rename (fun n : nat => n + 2) step)
      (Term.rename (fun n : nat => n + 2) idx))).
      repeat rewrite heval2.
      exact hcur.
    + split.
      * apply (proj2 (betaTermTermAt_nat_entry
        (scons nat next (scons nat cur e))
        (tVar 0)
        (Term.rename (fun n : nat => n + 2) code)
        (Term.rename (fun n : nat => n + 2) step)
        (tSucc (Term.rename (fun n : nat => n + 2) idx)))).
        simpl.
        repeat rewrite heval2.
        exact hnext.
      * apply (proj2 (div2StepTermAt_nat
        (scons nat next (scons nat cur e))
        (tVar 1) (tVar 0)
        (Term.rename (fun n : nat => n + 2) bit))).
        simpl.
        rewrite heval2.
        split; assumption.
Qed.

(* Lean: betaDiv2BitOneTermExAt_nat *)
Lemma betaDiv2BitOneTermExAt_nat : forall (e : nat -> nat) code step idx,
  Sat natModel e (betaDiv2BitOneTermExAt code step idx) <->
    BetaDiv2Bit
      (Term.eval natModel e code)
      (Term.eval natModel e step)
      (Term.eval natModel e idx)
      1.
Proof.
  intros e code step idx.
  unfold betaDiv2BitOneTermExAt. simpl.
  split.
  - intros [bit [hone hbit]].
    pose proof (proj1 (oneAt_nat (scons nat bit e) 0) hone) as hbitOne.
    pose proof (proj1 (betaDiv2BitTermAt_nat
      (scons nat bit e) (tVar 0)
      (Term.rename S code) (Term.rename S step)
      (Term.rename S idx)) hbit) as hbitTrace.
    repeat rewrite Term.eval_rename in hbitTrace.
    simpl in hbitTrace.
    subst bit.
    exact hbitTrace.
  - intro hbitTrace.
    exists 1.
    split.
    + apply (proj2 (oneAt_nat (scons nat 1 e) 0)).
      reflexivity.
    + apply (proj2 (betaDiv2BitTermAt_nat
      (scons nat 1 e) (tVar 0)
      (Term.rename S code) (Term.rename S step)
      (Term.rename S idx))).
      repeat rewrite Term.eval_rename.
      simpl.
      exact hbitTrace.
Qed.

Lemma hfMemAt_nat_trace : forall (e : nat -> nat) elem set,
  Sat natModel e (hfMemAt elem set) <->
    exists code step, HFMemTrace (e elem) (e set) code step.
Proof.
  intros e elem set.
  unfold hfMemAt. simpl.
  split.
  - intros [code [step [hstart [hsteps [bit [hone hbit]]]]]].
    pose (E := scons nat step (scons nat code e)).
    assert (hstart' : BetaEntry code step 0 (e set)).
    {
      pose proof (proj1 (betaAtConstIdx_nat_entry E (S (S set)) 1 0 0)
        hstart) as hs.
      unfold E in hs. simpl in hs. exact hs.
    }
    assert (hsteps' : BetaDiv2StepsThrough code step (e elem)).
    {
      pose proof (proj1 (betaDiv2StepsThroughAt_nat E 1 0 (S (S elem)))
        hsteps) as hs.
      unfold BetaDiv2StepsThrough.
      intros k hk.
      assert (hkE : k <= E (S (S elem))).
      {
        unfold E. simpl. exact hk.
      }
      destruct (hs k hkE) as [cur [next [b [hcur [hnext [hb hv]]]]]].
      exists cur, next, b.
      unfold BetaDiv2Step.
      unfold E in hcur, hnext. simpl in hcur, hnext.
      repeat split; assumption.
    }
    assert (hbit' : BetaDiv2Bit code step (e elem) 1).
    {
      pose proof (proj1 (oneAt_nat (scons nat bit E) 0) hone) as hone'.
      pose proof (proj1 (betaDiv2BitAt_nat (scons nat bit E)
        0 2 1 (S (S (S elem)))) hbit) as hb.
      unfold E in hb. simpl in hb.
      subst bit. exact hb.
    }
    exists code, step.
    unfold HFMemTrace.
    repeat split; assumption.
  - intros [code [step [hstart [hsteps hbit]]]].
    pose (E := scons nat step (scons nat code e)).
    exists code, step.
    repeat split.
    + apply (proj2 (betaAtConstIdx_nat_entry E (S (S set)) 1 0 0)).
      unfold E. simpl. exact hstart.
    + apply (proj2 (betaDiv2StepsThroughAt_nat E 1 0 (S (S elem)))).
      intros k hk.
      unfold E in hk. simpl in hk.
      destruct (hsteps k hk) as [cur [next [bit [hcur [hnext [hbit0 hval]]]]]].
      exists cur, next, bit.
      unfold E. simpl.
      repeat split; assumption.
    + exists 1.
      split.
      * apply (proj2 (oneAt_nat (scons nat 1 E) 0)).
        reflexivity.
      * apply (proj2 (betaDiv2BitAt_nat (scons nat 1 E)
          0 2 1 (S (S (S elem))))).
        unfold E. simpl. exact hbit.
Qed.

(* ===================================================================== *)
(*  Number-theoretic soundness of the beta / HF-membership coding          *)
(*  Coprimality, CRT, and the modulus lemmas proving the beta and          *)
(*  membership encodings meta-correct (hfMemAt sound and complete).        *)
(* ===================================================================== *)

Definition Coprime (m n : nat) : Prop := Nat.gcd m n = 1.

Lemma Coprime_1_l : forall n, Coprime 1 n.
Proof.
  intro n.
  unfold Coprime.
  apply Nat.gcd_unique.
  - exists 1. lia.
  - exists n. lia.
  - intros q hq _.
    exact hq.
Qed.

Lemma Coprime_sym : forall m n, Coprime m n -> Coprime n m.
Proof.
  unfold Coprime.
  intros m n h.
  rewrite Nat.gcd_comm.
  exact h.
Qed.

Lemma Coprime_of_dvd_left : forall d m n,
  Nat.divide d m -> Coprime m n -> Coprime d n.
Proof.
  unfold Coprime.
  intros d m n hdm hcop.
  apply Nat.gcd_unique.
  - exists d. lia.
  - exists n. lia.
  - intros q hqd hqn.
    assert (hqm : Nat.divide q m).
    {
      exact (Nat.divide_trans q d m hqd hdm).
    }
    pose proof (Nat.gcd_greatest m n q hqm hqn) as hqg.
    rewrite hcop in hqg.
    exact hqg.
Qed.

Lemma Coprime_eq_one_of_dvd : forall d n,
  Coprime d n -> Nat.divide d n -> d = 1.
Proof.
  unfold Coprime.
  intros d n hcop hdn.
  assert (hdg : Nat.divide d (Nat.gcd d n)).
  {
    apply Nat.gcd_greatest.
    - exists 1. lia.
    - exact hdn.
  }
  rewrite hcop in hdg.
  apply Nat.divide_1_r.
  exact hdg.
Qed.

Lemma Coprime_dvd_of_dvd_mul_left : forall d n k,
  Coprime d n -> Nat.divide d (k * n) -> Nat.divide d k.
Proof.
  unfold Coprime.
  intros d n k hcop hdkn.
  rewrite Nat.mul_comm in hdkn.
  exact (Nat.gauss d n k hdkn hcop).
Qed.

Lemma Coprime_mul_left : forall a b c,
  Coprime a c -> Coprime b c -> Coprime (a * b) c.
Proof.
  intros a b c hac hbc.
  unfold Coprime in *.
  apply Nat.gcd_unique.
  - exists (a * b). lia.
  - exists c. lia.
  - intros q hqprod hqc.
    assert (hq_b : Coprime q b).
    {
      apply Coprime_of_dvd_left with (m := c).
      - exact hqc.
      - apply Coprime_sym. exact hbc.
    }
    unfold Coprime in hq_b.
    assert (hqa : Nat.divide q a).
    {
      rewrite Nat.mul_comm in hqprod.
      exact (Nat.gauss q b a hqprod hq_b).
    }
    pose proof (Nat.gcd_greatest a c q hqa hqc) as hqg.
    rewrite hac in hqg.
    exact hqg.
Qed.

Lemma betaFact_pos : forall n, 0 < betaFact n.
Proof.
  induction n as [|n IH]; simpl; lia.
Qed.

Lemma dvd_betaFact_of_pos_le : forall k n,
  0 < k -> k <= n -> Nat.divide k (betaFact n).
Proof.
  intros k n hk hkn.
  induction n as [|n IH].
  - lia.
  - simpl.
    destruct (Nat.eq_dec k (S n)) as [heq | hne].
    + subst k.
      exists (betaFact n). nia.
    + assert (hkle : k <= n) by lia.
      destruct (IH hkle) as [q hq].
      exists (S n * q). nia.
Qed.

Lemma BetaModulus_pos : forall step idx, 0 < BetaModulus step idx.
Proof.
  intros step idx.
  unfold BetaModulus.
  lia.
Qed.

Lemma BetaModuliProduct_pos : forall step n,
  0 < BetaModuliProduct step n.
Proof.
  intros step n.
  induction n as [|n IH]; simpl.
  - lia.
  - pose proof (BetaModulus_pos step n).
    nia.
Qed.

Lemma BetaModulus_coprime_step : forall step idx,
  Coprime (BetaModulus step idx) step.
Proof.
  intros step idx.
  unfold Coprime.
  set (d := Nat.gcd (BetaModulus step idx) step).
  change (d = 1).
  assert (hdm : Nat.divide d (BetaModulus step idx)).
  {
    unfold d. apply Nat.gcd_divide_l.
  }
  assert (hdstep : Nat.divide d step).
  {
    unfold d. apply Nat.gcd_divide_r.
  }
  assert (hdprod : Nat.divide d (S idx * step)).
  {
    apply Nat.divide_mul_r.
    exact hdstep.
  }
  assert (hdone : Nat.divide d 1).
  {
    pose proof (Nat.divide_sub_r d (BetaModulus step idx)
      (S idx * step) hdm hdprod) as hsub.
    replace (BetaModulus step idx - S idx * step) with 1 in hsub
      by (unfold BetaModulus; nia).
    exact hsub.
  }
  apply Nat.divide_1_r.
  exact hdone.
Qed.

Lemma BetaModulus_sub : forall step i j,
  i <= j ->
  BetaModulus step j - BetaModulus step i = (j - i) * step.
Proof.
  intros step i j hij.
  unfold BetaModulus.
  nia.
Qed.

Lemma BetaModulus_pair_coprime_of_dvd_step : forall step i j,
  i < j ->
  Nat.divide (j - i) step ->
  Coprime (BetaModulus step i) (BetaModulus step j).
Proof.
  intros step i j hij hdiff.
  unfold Coprime.
  set (d := Nat.gcd (BetaModulus step i) (BetaModulus step j)).
  change (d = 1).
  assert (hdi : Nat.divide d (BetaModulus step i)).
  {
    unfold d. apply Nat.gcd_divide_l.
  }
  assert (hdj : Nat.divide d (BetaModulus step j)).
  {
    unfold d. apply Nat.gcd_divide_r.
  }
  assert (hcopStep : Coprime d step).
  {
    apply Coprime_of_dvd_left with (m := BetaModulus step i).
    - exact hdi.
    - apply BetaModulus_coprime_step.
  }
  assert (hddiffstep : Nat.divide d ((j - i) * step)).
  {
    pose proof (Nat.divide_sub_r d (BetaModulus step j)
      (BetaModulus step i) hdj hdi) as hsub.
    rewrite BetaModulus_sub in hsub by lia.
    exact hsub.
  }
  assert (hddiff : Nat.divide d (j - i)).
  {
    apply (Coprime_dvd_of_dvd_mul_left d step (j - i)).
    - exact hcopStep.
    - exact hddiffstep.
  }
  assert (hdstep' : Nat.divide d step).
  {
    exact (Nat.divide_trans d (j - i) step hddiff hdiff).
  }
  apply Coprime_eq_one_of_dvd with (n := step).
  - exact hcopStep.
  - exact hdstep'.
Qed.

Lemma BetaModulus_pair_coprime_of_lt_le : forall i j N,
  i < j -> j <= N ->
  Coprime (BetaModulus (betaFact N) i)
    (BetaModulus (betaFact N) j).
Proof.
  intros i j N hij hjN.
  apply BetaModulus_pair_coprime_of_dvd_step.
  - exact hij.
  - apply dvd_betaFact_of_pos_le; lia.
Qed.

Lemma BetaModuliProduct_coprime_modulus_of_le : forall n j N,
  n <= j -> j <= N ->
  Coprime (BetaModuliProduct (betaFact N) n)
    (BetaModulus (betaFact N) j).
Proof.
  intros n.
  induction n as [|n IH]; intros j N hnj hjN.
  - simpl.
    apply Coprime_1_l.
  - simpl.
    apply Coprime_mul_left.
    + apply IH; lia.
    + apply BetaModulus_pair_coprime_of_lt_le; lia.
Qed.

Lemma BetaModuliProduct_coprime_next_of_le : forall n N,
  n <= N ->
  Coprime (BetaModuliProduct (betaFact N) n)
    (BetaModulus (betaFact N) n).
Proof.
  intros n N hn.
  apply BetaModuliProduct_coprime_modulus_of_le; lia.
Qed.

Lemma BetaEntry_value_lt : forall code step idx value,
  BetaEntry code step idx value ->
  value < BetaModulus step idx.
Proof.
  intros code step idx value [_ [_ hlt]].
  exact hlt.
Qed.

Lemma BetaEntry_mod_eq : forall code step idx value,
  BetaEntry code step idx value ->
  code mod BetaModulus step idx = value.
Proof.
  intros code step idx value [q [hcode hlt]].
  rewrite hcode.
  rewrite Nat.add_comm.
  rewrite Nat.Div0.mod_add.
  apply Nat.mod_small.
  exact hlt.
Qed.

Lemma BetaEntry_of_mod_eq : forall code step idx value,
  value < BetaModulus step idx ->
  code mod BetaModulus step idx = value ->
  BetaEntry code step idx value.
Proof.
  intros code step idx value hlt hmod.
  exists (code / BetaModulus step idx).
  split.
  - rewrite <- hmod.
    rewrite Nat.mul_comm.
    apply Nat.div_mod_eq.
  - exact hlt.
Qed.

Lemma BetaModuliProduct_dvd_of_lt : forall step i n,
  i < n -> Nat.divide (BetaModulus step i) (BetaModuliProduct step n).
Proof.
  intros step i n hi.
  induction n as [|n IH].
  - lia.
  - simpl.
    destruct (Nat.eq_dec i n) as [heq | hne].
    + subst i.
      exists (BetaModuliProduct step n).
      reflexivity.
    + assert (hin : i < n) by lia.
      destruct (IH hin) as [q hq].
      exists (q * BetaModulus step n).
      rewrite hq.
      nia.
Qed.

Lemma mod_mod_of_dvd : forall a m d,
  0 < d -> Nat.divide d m -> (a mod m) mod d = a mod d.
Proof.
  intros a m d hdpos [q hq].
  subst m.
  replace (q * d) with (d * q) by nia.
  rewrite Nat.Div0.mod_mul_r.
  replace (d * ((a / d) mod q)) with (((a / d) mod q) * d) by nia.
  rewrite Nat.Div0.mod_add.
  apply Nat.mod_small.
  apply Nat.mod_upper_bound.
  lia.
Qed.

Lemma mod_eq_of_mod_BetaModuliProduct_eq :
    forall code old step idx n,
  idx < n ->
  code mod BetaModuliProduct step n =
    old mod BetaModuliProduct step n ->
  code mod BetaModulus step idx = old mod BetaModulus step idx.
Proof.
  intros code old step idx n hi hmod.
  pose proof (BetaModuliProduct_dvd_of_lt step idx n hi) as hd.
  pose proof (BetaModulus_pos step idx) as hpos.
  rewrite <- (mod_mod_of_dvd code (BetaModuliProduct step n)
    (BetaModulus step idx) hpos hd).
  rewrite hmod.
  apply mod_mod_of_dvd.
  - exact hpos.
  - exact hd.
Qed.

Lemma BetaEntry_of_mod_BetaModuliProduct_eq :
    forall code old step idx n value,
  idx < n ->
  code mod BetaModuliProduct step n =
    old mod BetaModuliProduct step n ->
  BetaEntry old step idx value ->
  BetaEntry code step idx value.
Proof.
  intros code old step idx n value hi hmod hold.
  apply BetaEntry_of_mod_eq.
  - exact (BetaEntry_value_lt old step idx value hold).
  - rewrite (mod_eq_of_mod_BetaModuliProduct_eq code old step idx n hi hmod).
    exact (BetaEntry_mod_eq old step idx value hold).
Qed.

Lemma BetaModulus_pair_coprime_of_lt_le_mul_betaFact :
    forall i j N scale,
  i < j -> j <= N ->
  Coprime (BetaModulus (betaFact N * scale) i)
    (BetaModulus (betaFact N * scale) j).
Proof.
  intros i j N scale hij hjN.
  apply BetaModulus_pair_coprime_of_dvd_step.
  - exact hij.
  - destruct (dvd_betaFact_of_pos_le (j - i) N) as [q hq]; try lia.
    exists (q * scale).
    rewrite hq.
    nia.
Qed.

Lemma BetaModuliProduct_coprime_modulus_of_le_mul_betaFact :
    forall n j N scale,
  n <= j -> j <= N ->
  Coprime (BetaModuliProduct (betaFact N * scale) n)
    (BetaModulus (betaFact N * scale) j).
Proof.
  intros n.
  induction n as [|n IH]; intros j N scale hnj hjN.
  - simpl.
    apply Coprime_1_l.
  - simpl.
    apply Coprime_mul_left.
    + apply IH; lia.
    + apply BetaModulus_pair_coprime_of_lt_le_mul_betaFact; lia.
Qed.

Lemma BetaModuliProduct_coprime_next_of_le_mul_betaFact :
    forall n N scale,
  n <= N ->
  Coprime (BetaModuliProduct (betaFact N * scale) n)
    (BetaModulus (betaFact N * scale) n).
Proof.
  intros n N scale hn.
  apply BetaModuliProduct_coprime_modulus_of_le_mul_betaFact; lia.
Qed.

Lemma coprime_bezout_left : forall m n,
  0 < m -> Coprime m n -> exists x y, x * m = 1 + y * n.
Proof.
  intros m n hm hcop.
  unfold Coprime in hcop.
  destruct (Nat.gcd_bezout_pos m n hm) as [x [y hxy]].
  rewrite hcop in hxy.
  exists x, y.
  exact hxy.
Qed.

Lemma crt_two_mod : forall m n a b,
  0 < m -> 0 < n -> Coprime m n -> a < m -> b < n ->
  exists c, c mod m = a /\ c mod n = b.
Proof.
  intros m n a b hm hn hcop ha hb.
  destruct (coprime_bezout_left m n hm hcop) as [x [y hxy]].
  set (delta := b + n - a mod n).
  exists (a + m * (x * delta)).
  split.
  - replace (m * (x * delta)) with ((x * delta) * m) by nia.
    rewrite Nat.Div0.mod_add.
    apply Nat.mod_small.
    exact ha.
  - assert (hdelta : (a + delta) mod n = b).
    {
      unfold delta.
      assert (hnneq : n <> 0) by lia.
      pose proof (Nat.mod_upper_bound a n hnneq) as hr.
      pose proof (Nat.div_mod_eq a n) as hdiv.
      replace (a + (b + n - a mod n)) with
        (b + (a / n + 1) * n) by nia.
      rewrite Nat.Div0.mod_add.
      apply Nat.mod_small.
      exact hb.
    }
    assert (hmx : m * x = 1 + y * n) by nia.
    replace (m * (x * delta)) with (delta + (y * delta) * n) by nia.
    replace (a + (delta + y * delta * n)) with
      ((a + delta) + (y * delta) * n) by nia.
    rewrite Nat.Div0.mod_add.
    exact hdelta.
Qed.

Lemma beta_entries_exist_lt_mul_betaFact :
    forall N n scale,
  n <= S N ->
  forall value : nat -> nat,
  (forall i, i < n ->
    value i < BetaModulus (betaFact N * scale) i) ->
  exists code,
    forall i, i < n ->
      BetaEntry code (betaFact N * scale) i (value i).
Proof.
  intros N n.
  induction n as [|n IH]; intros scale hn value hsmall.
  - exists 0.
    intros i hi.
    lia.
  - assert (hnOld : n <= S N) by lia.
    destruct (IH scale hnOld value) as [old hold].
    {
      intros i hi.
      apply hsmall.
      lia.
    }
    set (step := betaFact N * scale).
    set (prod := BetaModuliProduct step n).
    set (modn := BetaModulus step n).
    assert (hprodPos : 0 < prod).
    {
      unfold prod.
      apply BetaModuliProduct_pos.
    }
    assert (hmodnPos : 0 < modn).
    {
      unfold modn.
      apply BetaModulus_pos.
    }
    assert (hnN : n <= N) by lia.
    assert (hcop : Coprime prod modn).
    {
      unfold prod, modn, step.
      apply BetaModuliProduct_coprime_next_of_le_mul_betaFact.
      exact hnN.
    }
    assert (ha : old mod prod < prod).
    {
      apply Nat.mod_upper_bound.
      lia.
    }
    assert (hb : value n < modn).
    {
      unfold modn, step.
      apply hsmall.
      lia.
    }
    destruct (crt_two_mod prod modn (old mod prod) (value n)
      hprodPos hmodnPos hcop ha hb) as [code [hprod hnew]].
    exists code.
    intros i hi.
    destruct (Nat.eq_dec i n) as [heq | hne].
    + subst i.
      apply BetaEntry_of_mod_eq.
      * unfold step.
        apply hsmall.
        lia.
      * unfold modn in hnew.
        exact hnew.
    + assert (hin : i < n) by lia.
      apply BetaEntry_of_mod_BetaModuliProduct_eq with (old := old) (n := n).
      * exact hin.
      * unfold prod in hprod.
        exact hprod.
      * apply hold.
        exact hin.
Qed.

Lemma beta_entries_exist_through_mul_betaFact :
    forall N scale (value : nat -> nat),
  (forall i, i <= N ->
    value i < BetaModulus (betaFact N * scale) i) ->
  exists code,
    forall i, i <= N ->
      BetaEntry code (betaFact N * scale) i (value i).
Proof.
  intros N scale value hsmall.
  assert (hN : S N <= S N) by lia.
  destruct (beta_entries_exist_lt_mul_betaFact N (S N) scale
    hN value) as [code hcode].
  {
    intros i hi.
    apply hsmall.
    lia.
  }
  exists code.
  intros i hi.
  apply hcode.
  lia.
Qed.

Lemma shiftr_succ_div2 : forall set k,
  Nat.shiftr set (S k) = Nat.shiftr set k / 2.
Proof.
  intros set k.
  replace (S k) with (k + 1) by lia.
  rewrite <- (Nat.shiftr_shiftr set k 1).
  rewrite Nat.shiftr_div_pow2.
  simpl.
  reflexivity.
Qed.

Lemma shiftRight_lt_trace_modulus : forall elem set i,
  Nat.shiftr set i <
    BetaModulus (betaFact (S elem) * S set) i.
Proof.
  intros elem set i.
  pose proof (Nat.shiftr_upper_bound set i) as hshift.
  pose proof (betaFact_pos (S elem)) as hbf.
  unfold BetaModulus.
  nia.
Qed.

Lemma mod_two_eq_zero_or_one : forall n, n mod 2 = 0 \/ n mod 2 = 1.
Proof.
  intro n.
  assert (h2 : 2 <> 0) by lia.
  pose proof (Nat.mod_upper_bound n 2 h2) as h.
  lia.
Qed.

Lemma div2_step_shiftr : forall set k,
  let cur := Nat.shiftr set k in
  let next := Nat.shiftr set (S k) in
  let bit := cur mod 2 in
  (bit = 0 \/ bit = 1) /\ cur = next + next + bit.
Proof.
  intros set k cur next bit.
  assert (hbit : bit = 0 \/ bit = 1).
  {
    unfold bit.
    apply mod_two_eq_zero_or_one.
  }
  assert (hnext : next = cur / 2).
  {
    unfold next, cur.
    apply shiftr_succ_div2.
  }
  pose proof (Nat.div_mod_eq cur 2) as hdiv.
  split.
  - exact hbit.
  - unfold bit.
    nia.
Qed.

Lemma div2_step_shiftr_one : forall set elem,
  hf_mem elem set ->
  let cur := Nat.shiftr set elem in
  let next := Nat.shiftr set (S elem) in
  cur = next + next + 1.
Proof.
  intros set elem hmem cur next.
  assert (hbitTrue : Nat.testbit cur 0 = true).
  {
    unfold cur.
    rewrite Nat.shiftr_spec'.
    replace (0 + elem) with elem by lia.
    unfold hf_mem in hmem.
    exact hmem.
  }
  pose proof (Nat.bit0_mod cur) as hbitmod.
  rewrite hbitTrue in hbitmod.
  simpl in hbitmod.
  assert (hmod : cur mod 2 = 1).
  {
    symmetry.
    exact hbitmod.
  }
  assert (hnext : next = cur / 2).
  {
    unfold next, cur.
    apply shiftr_succ_div2.
  }
  pose proof (Nat.div_mod_eq cur 2) as hdiv.
  nia.
Qed.

Lemma HFMemTrace_exists_of_mem : forall elem set,
  hf_mem elem set -> exists code step, HFMemTrace elem set code step.
Proof.
  intros elem set hmem.
  set (N := S elem).
  set (scale := S set).
  set (step := betaFact N * scale).
  set (value := fun k => Nat.shiftr set k).
  assert (hsmall : forall i, i <= N -> value i < BetaModulus step i).
  {
    intros i _.
    unfold value, step, N, scale.
    apply shiftRight_lt_trace_modulus.
  }
  destruct (beta_entries_exist_through_mul_betaFact N scale value hsmall)
    as [code hcode].
  exists code, step.
  unfold HFMemTrace.
  split.
  - assert (h0le : 0 <= N) by lia.
    pose proof (hcode 0 h0le) as h0.
    unfold value in h0.
    rewrite Nat.shiftr_0_r in h0.
    exact h0.
  - split.
    + unfold BetaDiv2StepsThrough.
      intros k hk.
      set (cur := Nat.shiftr set k).
      set (next := Nat.shiftr set (S k)).
      set (bit := cur mod 2).
      assert (hcur : BetaEntry code step k cur).
      {
        assert (hkle : k <= N) by lia.
        pose proof (hcode k hkle) as h.
        unfold value in h.
        exact h.
      }
      assert (hnext : BetaEntry code step (S k) next).
      {
        assert (hskle : S k <= N) by lia.
        pose proof (hcode (S k) hskle) as h.
        unfold value in h.
        exact h.
      }
      pose proof (div2_step_shiftr set k) as hstep.
      exists cur, next, bit.
      unfold BetaDiv2Step.
      repeat split.
      * exact hcur.
      * exact hnext.
      * unfold cur, bit in hstep.
        exact (proj1 hstep).
      * unfold cur, next, bit in hstep.
        exact (proj2 hstep).
    + unfold BetaDiv2Bit.
      set (cur := Nat.shiftr set elem).
      set (next := Nat.shiftr set (S elem)).
      assert (hcur : BetaEntry code step elem cur).
      {
        assert (hemle : elem <= N) by lia.
        pose proof (hcode elem hemle) as h.
        unfold value in h.
        exact h.
      }
      assert (hnext : BetaEntry code step (S elem) next).
      {
        assert (hsemle : S elem <= N) by lia.
        pose proof (hcode (S elem) hsemle) as h.
        unfold value in h.
        exact h.
      }
      assert (hcurEq : cur = next + next + 1).
      {
        unfold cur, next.
        apply div2_step_shiftr_one.
        exact hmem.
      }
      exists cur, next.
      unfold BetaDiv2Step.
      repeat split.
      * exact hcur.
      * exact hnext.
      * right. reflexivity.
      * exact hcurEq.
Qed.

Lemma BProv_Ax_s_hfMemAt_of_eqConst_mem :
  forall G elem set elemValue setValue,
  BProv Ax_s G (eqConstAt elem elemValue) ->
  BProv Ax_s G (eqConstAt set setValue) ->
  hf_mem elemValue setValue ->
  BProv Ax_s G (hfMemAt elem set).
Proof.
  intros G elem set elemValue setValue helem hset hmem.
  destruct (HFMemTrace_exists_of_mem elemValue setValue hmem) as
    [code [step htrace]].
  exact (BProv_Ax_s_hfMemAt_of_eqConst_trace
    G elem set elemValue setValue code step helem hset htrace).
Qed.

Lemma BetaEntry_functional : forall code step idx a b,
  BetaEntry code step idx a -> BetaEntry code step idx b -> a = b.
Proof.
  intros code step idx a b ha hb.
  transitivity (code mod BetaModulus step idx).
  - symmetry. apply BetaEntry_mod_eq. exact ha.
  - apply BetaEntry_mod_eq. exact hb.
Qed.

Lemma BetaDiv2Step_div_two : forall code step idx cur next bit,
  BetaDiv2Step code step idx cur next bit -> cur / 2 = next.
Proof.
  intros code step idx cur next bit [_ [_ [hbit hcur]]].
  destruct hbit as [hbit | hbit]; subst bit; rewrite hcur.
  - replace (next + next + 0) with (2 * next + 0) by lia.
    symmetry.
    apply Nat.div_unique with (r := 0); lia.
  - replace (next + next + 1) with (2 * next + 1) by lia.
    symmetry.
    apply Nat.div_unique with (r := 1); lia.
Qed.

Lemma BetaDiv2Step_bit_one_testbit_zero :
    forall code step idx cur next,
  BetaDiv2Step code step idx cur next 1 ->
  Nat.testbit cur 0 = true.
Proof.
  intros code step idx cur next [_ [_ [_ hcur]]].
  rewrite hcur.
  replace (next + next + 1) with (2 * next + 1) by lia.
  apply Nat.testbit_odd_0.
Qed.


(* Lean: div2Iter *)
Fixpoint div2Iter (value k : nat) : nat :=
  match k with
  | 0 => value
  | S n => div2Iter value n / 2
  end.

(* Lean: div2Iter_eq_shiftRight *)
Lemma div2Iter_eq_shiftr : forall value k,
  div2Iter value k = Nat.shiftr value k.
Proof.
  intros value k.
  induction k as [|k IH].
  - reflexivity.
  - change (div2Iter value (S k)) with (div2Iter value k / 2).
    rewrite IH.
    rewrite (shiftr_succ_div2 value k).
    reflexivity.
Qed.

(* Lean: div2Iter_mod_two_eq_zero_of_not_mem *)
Lemma div2Iter_mod_two_eq_zero_of_not_mem : forall elem set,
  ~ hf_mem elem set ->
  div2Iter set elem mod 2 = 0.
Proof.
  intros elem set hnot.
  rewrite div2Iter_eq_shiftr.
  pose proof (hf_testbit_false_of_not_mem elem set hnot) as hbit.
  assert (hshift : Nat.testbit (Nat.shiftr set elem) 0 = false).
  {
    rewrite Nat.shiftr_spec'.
    replace (0 + elem) with elem by lia.
    exact hbit.
  }
  apply hf_testbit0_false_iff.
  exact hshift.
Qed.

(* Lean: BetaDiv2StepsThrough_entry_shiftRight *)
Lemma BetaDiv2StepsThrough_entry_shiftr : forall elem set code step,
  BetaEntry code step 0 set ->
  BetaDiv2StepsThrough code step elem ->
  forall k value,
    k <= S elem ->
    BetaEntry code step k value ->
    value = Nat.shiftr set k.
Proof.
  intros elem set code step hentry hsteps k.
  induction k as [|k IH]; intros value hle hvalue.
  - pose proof (BetaEntry_functional code step 0 value set
      hvalue hentry) as hv.
    rewrite Nat.shiftr_0_r.
    exact hv.
  - assert (hk : k <= elem) by lia.
    destruct (hsteps k hk) as [cur [next [bit hstep]]].
    assert (hcur : cur = Nat.shiftr set k).
    {
      apply IH.
      - lia.
      - exact (proj1 hstep).
    }
    assert (hvalue_next : value = next).
    {
      apply BetaEntry_functional with (code := code) (step := step)
        (idx := S k).
      - exact hvalue.
      - exact (proj1 (proj2 hstep)).
    }
    rewrite hvalue_next.
    transitivity (cur / 2).
    + symmetry.
      apply BetaDiv2Step_div_two with
        (code := code) (step := step) (idx := k) (bit := bit).
      exact hstep.
    + rewrite hcur.
      symmetry.
      apply shiftr_succ_div2.
Qed.

(* Lean: BetaDiv2Step_bit_zero_of_not_mem *)
Lemma BetaDiv2Step_bit_zero_of_not_mem :
  forall elem set code step cur next bit,
  BetaEntry code step 0 set ->
  BetaDiv2StepsThrough code step elem ->
  BetaDiv2Step code step elem cur next bit ->
  ~ hf_mem elem set ->
  bit = 0.
Proof.
  intros elem set code step cur next bit hentry hsteps hstep hnot.
  assert (hcur : cur = Nat.shiftr set elem).
  {
    apply (BetaDiv2StepsThrough_entry_shiftr elem set code step
      hentry hsteps elem cur).
    - lia.
    - exact (proj1 hstep).
  }
  destruct hstep as [hc [hn [hbit hshape]]].
  destruct hbit as [hbit0 | hbit1]; [exact hbit0 |].
  exfalso.
  subst bit.
  pose proof (div2Iter_mod_two_eq_zero_of_not_mem elem set hnot) as hmod.
  rewrite div2Iter_eq_shiftr in hmod.
  rewrite <- hcur in hmod.
  rewrite hshape in hmod.
  replace (next + next + 1) with (1 + next * 2) in hmod by lia.
  rewrite Nat.Div0.mod_add in hmod.
  simpl in hmod.
  discriminate.
Qed.

(* Lean: BetaDiv2Step_current_double_of_not_mem *)
Lemma BetaDiv2Step_current_double_of_not_mem :
  forall elem set code step cur next bit,
  BetaEntry code step 0 set ->
  BetaDiv2StepsThrough code step elem ->
  BetaDiv2Step code step elem cur next bit ->
  ~ hf_mem elem set ->
  cur = next + next.
Proof.
  intros elem set code step cur next bit hentry hsteps hstep hnot.
  pose proof (BetaDiv2Step_bit_zero_of_not_mem elem set code step
    cur next bit hentry hsteps hstep hnot) as hbit.
  destruct hstep as [_ [_ [_ hshape]]].
  lia.
Qed.

Lemma HFMemTrace_entry_shiftr : forall elem set code step,
  HFMemTrace elem set code step ->
  forall k value,
    k <= S elem ->
    BetaEntry code step k value ->
    value = Nat.shiftr set k.
Proof.
  intros elem set code step htrace.
  destruct htrace as [hentry [hsteps _]].
  exact (BetaDiv2StepsThrough_entry_shiftr elem set code step
    hentry hsteps).
Qed.

Lemma HFMemTrace_mem : forall elem set code step,
  HFMemTrace elem set code step -> hf_mem elem set.
Proof.
  intros elem set code step htrace.
  destruct htrace as [hstart [hsteps hbitTrace]].
  destruct hbitTrace as [cur [next hstep]].
  assert (htraceFull : HFMemTrace elem set code step).
  {
    unfold HFMemTrace.
    split.
    - exact hstart.
    - split.
      + exact hsteps.
      + exists cur, next.
        exact hstep.
  }
  assert (hcur : cur = Nat.shiftr set elem).
  {
    apply (HFMemTrace_entry_shiftr elem set code step htraceFull elem cur).
    - lia.
    - exact (proj1 hstep).
  }
  pose proof (BetaDiv2Step_bit_one_testbit_zero
    code step elem cur next hstep) as hlow.
  rewrite hcur in hlow.
  unfold hf_mem.
  rewrite Nat.shiftr_spec' in hlow.
  replace (0 + elem) with elem in hlow by lia.
  exact hlow.
Qed.

Lemma hfMemAt_sound : forall (e : nat -> nat) elem set,
  Sat natModel e (hfMemAt elem set) -> hf_mem (e elem) (e set).
Proof.
  intros e elem set h.
  destruct (proj1 (hfMemAt_nat_trace e elem set) h) as
    [code [step htrace]].
  exact (HFMemTrace_mem (e elem) (e set) code step htrace).
Qed.

Lemma hfMemAt_complete : forall (e : nat -> nat) elem set,
  hf_mem (e elem) (e set) -> Sat natModel e (hfMemAt elem set).
Proof.
  intros e elem set hmem.
  destruct (HFMemTrace_exists_of_mem (e elem) (e set) hmem) as
    [code [step htrace]].
  apply (proj2 (hfMemAt_nat_trace e elem set)).
  exists code, step.
  exact htrace.
Qed.

Lemma hfMemAt_exact : forall (e : nat -> nat) elem set,
  Sat natModel e (hfMemAt elem set) <-> hf_mem (e elem) (e set).
Proof.
  intros e elem set.
  split.
  - apply hfMemAt_sound.
  - apply hfMemAt_complete.
Qed.

Lemma hfMemAt_free : forall i elem set,
  Free i (hfMemAt elem set) -> i = elem \/ i = set.
Proof.
  intros i elem set h.
  unfold hfMemAt, betaDiv2BitAt, betaDiv2StepsThroughAt,
    betaDiv2StepWitnessAt, betaAtConstIdx, betaAtSuccIdx, betaAt,
    remAt, ltAt, leAt, div2StepAt, boolAt, zeroAt, oneAt,
    eqConstAt, betaModTerm in h.
  simpl in h.
  lia.
Qed.

(* ===================================================================== *)
(*  HF-to-PA formula translation and provability lifting                   *)
(*  hfFormulaAt translating HF formulas into PA, with exactness and the     *)
(*  lifting of HF-provability into PA-provability.                          *)
(* ===================================================================== *)

Definition hfUpVarMap (rho : nat -> nat) : nat -> nat :=
  fun n =>
    match n with
    | 0 => 0
    | S k => S (rho k)
    end.

Fixpoint hfFormulaAt (rho : nat -> nat) (phi : form) : formula :=
  match phi with
  | fMem i j => hfMemAt (rho i) (rho j)
  | fEq i j => pEq (tVar (rho i)) (tVar (rho j))
  | fBot => pBot
  | fImp a b => pImp (hfFormulaAt rho a) (hfFormulaAt rho b)
  | fAnd a b => pAnd (hfFormulaAt rho a) (hfFormulaAt rho b)
  | fOr a b => pOr (hfFormulaAt rho a) (hfFormulaAt rho b)
  | fAll a => pAll (hfFormulaAt (hfUpVarMap rho) a)
  | fEx a => pEx (hfFormulaAt (hfUpVarMap rho) a)
  end.

Definition translateHFFormula (phi : form) : formula :=
  hfFormulaAt (fun n => n) phi.

Definition hfContextAt (rho : nat -> nat) (G : list form) : list formula :=
  map (hfFormulaAt rho) G.

Definition translateHFContext (G : list form) : list formula :=
  map translateHFFormula G.

Lemma BProv_Ax_s_HF_empty_zero_body_of_member_bot :
  BProv Ax_s [subst (Term.upSubst (instTerm tZero)) (hfMemAt 0 1)] pBot ->
  BProv Ax_s []
    (subst (instTerm tZero)
      (pAll (pImp (hfMemAt 0 1) pBot))).
Proof.
  intro hmem.
  set (memZero := subst (Term.upSubst (instTerm tZero)) (hfMemAt 0 1)).
  assert (hmem' : BProv Ax_s [memZero] pBot).
  {
    unfold memZero.
    exact hmem.
  }
  pose proof (BProv_impI Ax_s [] memZero pBot hmem') as himp.
  pose proof (BProv_allI_of_sentences Ax_s []
    (pImp memZero pBot) sentence_ax_s himp) as hall.
  unfold memZero in hall.
  simpl in *.
  exact hall.
Qed.

Lemma BProv_Ax_s_translated_HF_empty_of_zero_body :
  BProv Ax_s []
    (subst (instTerm tZero)
      (pAll (pImp (hfMemAt 0 1) pBot))) ->
  BProv Ax_s []
    (translateHFFormula (seal HF_empty_form)).
Proof.
  intro hbody.
  set (body := pAll (pImp (hfMemAt 0 1) pBot)).
  assert (hex : BProv Ax_s [] (pEx body)).
  {
    exact (BProv_exI Ax_s [] body tZero hbody).
  }
  pose proof (BProv_allI_of_sentences Ax_s []
    (pEx body) sentence_ax_s hex) as h1.
  pose proof (BProv_allI_of_sentences Ax_s []
    (pAll (pEx body)) sentence_ax_s h1) as h2.
  pose proof (BProv_allI_of_sentences Ax_s []
    (pAll (pAll (pEx body))) sentence_ax_s h2) as h3.
  unfold translateHFFormula, HF_empty_form, seal, Fol.closeN, Fol.bound.
  simpl.
  fold body.
  exact h3.
Qed.

Lemma BProv_Ax_s_translated_HF_empty_of_zero_member_bot :
  BProv Ax_s [subst (Term.upSubst (instTerm tZero)) (hfMemAt 0 1)] pBot ->
  BProv Ax_s []
    (translateHFFormula (seal HF_empty_form)).
Proof.
  intro hmem.
  exact (BProv_Ax_s_translated_HF_empty_of_zero_body
    (BProv_Ax_s_HF_empty_zero_body_of_member_bot hmem)).
Qed.

Lemma translateHFContext_eq_hfContextAt_id : forall G,
  translateHFContext G = hfContextAt (fun n => n) G.
Proof.
  intro G.
  unfold translateHFContext, hfContextAt, translateHFFormula.
  reflexivity.
Qed.

Lemma hfFormulaAt_exact : forall phi rho v e,
  (forall n, e (rho n) = v n) ->
  Sat natModel e (hfFormulaAt rho phi) <->
    Fol.Sat nat hf_mem v phi.
Proof.
  induction phi; simpl; intros rho v e hrho.
  - change (Sat natModel e (hfMemAt (rho n) (rho n0)) <->
      hf_mem (v n) (v n0)).
    rewrite hfMemAt_exact.
    rewrite hrho, hrho.
    reflexivity.
  - split; intro h.
    + rewrite <- (hrho n), <- (hrho n0).
      exact h.
    + rewrite (hrho n), (hrho n0).
      exact h.
  - reflexivity.
  - specialize (IHphi1 rho v e hrho).
    specialize (IHphi2 rho v e hrho).
    split; intros h ha.
    + apply (proj1 IHphi2).
      apply h.
      apply (proj2 IHphi1).
      exact ha.
    + apply (proj2 IHphi2).
      apply h.
      apply (proj1 IHphi1).
      exact ha.
  - specialize (IHphi1 rho v e hrho).
    specialize (IHphi2 rho v e hrho).
    split; intros h.
    + split.
      * apply (proj1 IHphi1). exact (proj1 h).
      * apply (proj1 IHphi2). exact (proj2 h).
    + split.
      * apply (proj2 IHphi1). exact (proj1 h).
      * apply (proj2 IHphi2). exact (proj2 h).
  - specialize (IHphi1 rho v e hrho).
    specialize (IHphi2 rho v e hrho).
    split; intros h.
    + destruct h as [h | h].
      * left. apply (proj1 IHphi1). exact h.
      * right. apply (proj1 IHphi2). exact h.
    + destruct h as [h | h].
      * left. apply (proj2 IHphi1). exact h.
      * right. apply (proj2 IHphi2). exact h.
  - split; intros h d.
    + assert (hrho' : forall n,
        scons nat d e (hfUpVarMap rho n) = scons nat d v n).
      {
        intros [|n]; simpl.
        - reflexivity.
        - apply hrho.
      }
      apply (proj1 (IHphi (hfUpVarMap rho)
        (scons nat d v) (scons nat d e) hrho')).
      exact (h d).
    + assert (hrho' : forall n,
        scons nat d e (hfUpVarMap rho n) = scons nat d v n).
      {
        intros [|n]; simpl.
        - reflexivity.
        - apply hrho.
      }
      apply (proj2 (IHphi (hfUpVarMap rho)
        (scons nat d v) (scons nat d e) hrho')).
      exact (h d).
  - split; intros h.
    + destruct h as [d hd].
      exists d.
      assert (hrho' : forall n,
        scons nat d e (hfUpVarMap rho n) = scons nat d v n).
      {
        intros [|n]; simpl.
        - reflexivity.
        - apply hrho.
      }
      apply (proj1 (IHphi (hfUpVarMap rho)
        (scons nat d v) (scons nat d e) hrho')).
      exact hd.
    + destruct h as [d hd].
      exists d.
      assert (hrho' : forall n,
        scons nat d e (hfUpVarMap rho n) = scons nat d v n).
      {
        intros [|n]; simpl.
        - reflexivity.
        - apply hrho.
      }
      apply (proj2 (IHphi (hfUpVarMap rho)
        (scons nat d v) (scons nat d e) hrho')).
      exact hd.
Qed.

Lemma translateHFFormula_exact : forall phi v,
  Sat natModel v (translateHFFormula phi) <->
    Fol.Sat nat hf_mem v phi.
Proof.
  intros phi v.
  unfold translateHFFormula.
  apply hfFormulaAt_exact.
  intro n. reflexivity.
Qed.

Lemma hfFormulaAt_free : forall phi rho i,
  Free i (hfFormulaAt rho phi) ->
    exists n, Fol.Free n phi /\ i = rho n.
Proof.
  induction phi; simpl; intros rho i h.
  - destruct (hfMemAt_free i (rho n) (rho n0) h) as [hi | hi].
    + exists n. split; [left; reflexivity | exact hi].
    + exists n0. split; [right; reflexivity | exact hi].
  - destruct h as [h | h].
    + exists n. split; [left; reflexivity | exact h].
    + exists n0. split; [right; reflexivity | exact h].
  - contradiction.
  - destruct h as [h | h].
    + destruct (IHphi1 rho i h) as [n [hn hi]].
      exists n. split; [left; exact hn | exact hi].
    + destruct (IHphi2 rho i h) as [n [hn hi]].
      exists n. split; [right; exact hn | exact hi].
  - destruct h as [h | h].
    + destruct (IHphi1 rho i h) as [n [hn hi]].
      exists n. split; [left; exact hn | exact hi].
    + destruct (IHphi2 rho i h) as [n [hn hi]].
      exists n. split; [right; exact hn | exact hi].
  - destruct h as [h | h].
    + destruct (IHphi1 rho i h) as [n [hn hi]].
      exists n. split; [left; exact hn | exact hi].
    + destruct (IHphi2 rho i h) as [n [hn hi]].
      exists n. split; [right; exact hn | exact hi].
  - destruct (IHphi (hfUpVarMap rho) (S i) h) as [n [hn hi]].
    destruct n as [|n].
    + simpl in hi. discriminate hi.
    + exists n.
      split.
      * exact hn.
      * simpl in hi.
        injection hi as hi.
        exact hi.
  - destruct (IHphi (hfUpVarMap rho) (S i) h) as [n [hn hi]].
    destruct n as [|n].
    + simpl in hi. discriminate hi.
    + exists n.
      split.
      * exact hn.
      * simpl in hi.
        injection hi as hi.
        exact hi.
Qed.

Lemma hfFormulaAt_ext : forall phi rho sigma,
  (forall n, rho n = sigma n) ->
    hfFormulaAt rho phi = hfFormulaAt sigma phi.
Proof.
  induction phi; simpl; intros rho sigma h; try reflexivity.
  - now rewrite (h n), (h n0).
  - now rewrite (h n), (h n0).
  - now rewrite (IHphi1 rho sigma h), (IHphi2 rho sigma h).
  - now rewrite (IHphi1 rho sigma h), (IHphi2 rho sigma h).
  - now rewrite (IHphi1 rho sigma h), (IHphi2 rho sigma h).
  - f_equal.
    apply IHphi.
    intros [|n]; simpl; [reflexivity | now rewrite h].
  - f_equal.
    apply IHphi.
    intros [|n]; simpl; [reflexivity | now rewrite h].
Qed.

Lemma hfFormulaAt_ext_free : forall phi rho sigma,
  (forall n, Fol.Free n phi -> rho n = sigma n) ->
    hfFormulaAt rho phi = hfFormulaAt sigma phi.
Proof.
  induction phi; simpl; intros rho sigma h; try reflexivity.
  - rewrite (h n (or_introl eq_refl)).
    rewrite (h n0 (or_intror eq_refl)).
    reflexivity.
  - rewrite (h n (or_introl eq_refl)).
    rewrite (h n0 (or_intror eq_refl)).
    reflexivity.
  - rewrite (IHphi1 rho sigma (fun n hn => h n (or_introl hn))).
    rewrite (IHphi2 rho sigma (fun n hn => h n (or_intror hn))).
    reflexivity.
  - rewrite (IHphi1 rho sigma (fun n hn => h n (or_introl hn))).
    rewrite (IHphi2 rho sigma (fun n hn => h n (or_intror hn))).
    reflexivity.
  - rewrite (IHphi1 rho sigma (fun n hn => h n (or_introl hn))).
    rewrite (IHphi2 rho sigma (fun n hn => h n (or_intror hn))).
    reflexivity.
  - f_equal.
    apply IHphi.
    intros [|n] hn; simpl; [reflexivity |].
    now rewrite (h n hn).
  - f_equal.
    apply IHphi.
    intros [|n] hn; simpl; [reflexivity |].
    now rewrite (h n hn).
Qed.

Lemma hfFormulaAt_source_rename : forall phi rho r,
  hfFormulaAt rho (Fol.rename r phi) =
    hfFormulaAt (fun n => rho (r n)) phi.
Proof.
  induction phi; simpl; intros rho r; try reflexivity.
  - now rewrite (IHphi1 rho r), (IHphi2 rho r).
  - now rewrite (IHphi1 rho r), (IHphi2 rho r).
  - now rewrite (IHphi1 rho r), (IHphi2 rho r).
  - rewrite (IHphi (hfUpVarMap rho) (Fol.up r)).
    f_equal.
    apply hfFormulaAt_ext.
    intros [|n]; reflexivity.
  - rewrite (IHphi (hfUpVarMap rho) (Fol.up r)).
    f_equal.
    apply hfFormulaAt_ext.
    intros [|n]; reflexivity.
Qed.

Lemma rename_hfFormulaAt : forall phi rho r,
  rename r (hfFormulaAt rho phi) =
    hfFormulaAt (fun n => r (rho n)) phi.
Proof.
  induction phi; simpl; intros rho r; try reflexivity.
  - now rewrite (IHphi1 rho r), (IHphi2 rho r).
  - now rewrite (IHphi1 rho r), (IHphi2 rho r).
  - now rewrite (IHphi1 rho r), (IHphi2 rho r).
  - rewrite (IHphi (hfUpVarMap rho) (up r)).
    f_equal.
    apply hfFormulaAt_ext.
    intros [|n]; reflexivity.
  - rewrite (IHphi (hfUpVarMap rho) (up r)).
    f_equal.
    apply hfFormulaAt_ext.
    intros [|n]; reflexivity.
Qed.

Lemma hfFormulaAt_rename_succ : forall phi rho,
  hfFormulaAt (hfUpVarMap rho) (Fol.rename S phi) =
    rename S (hfFormulaAt rho phi).
Proof.
  intros phi rho.
  rewrite (hfFormulaAt_source_rename phi (hfUpVarMap rho) S).
  rewrite (hfFormulaAt_ext phi
    (fun n => hfUpVarMap rho (S n)) (fun n => S (rho n))).
  - symmetry.
    apply rename_hfFormulaAt.
  - intro n. reflexivity.
Qed.

Lemma hfContextAt_rename_succ : forall rho G,
  hfContextAt (hfUpVarMap rho) (map (Fol.rename S) G) =
    map (rename S) (hfContextAt rho G).
Proof.
  intros rho G.
  induction G as [|phi G IH]; simpl.
  - reflexivity.
  - rewrite hfFormulaAt_rename_succ.
    now rewrite IH.
Qed.

Lemma hfContextAt_cons_rename_succ : forall rho a G,
  hfContextAt (hfUpVarMap rho) (a :: map (Fol.rename S) G) =
    hfFormulaAt (hfUpVarMap rho) a :: map (rename S) (hfContextAt rho G).
Proof.
  intros rho a G.
  simpl.
  rewrite hfContextAt_rename_succ.
  reflexivity.
Qed.

Lemma subst_instTerm_var_hfFormulaAt : forall phi rho k,
  subst (instTerm (tVar (rho k))) (hfFormulaAt (hfUpVarMap rho) phi) =
    hfFormulaAt rho (Fol.rename (Fol.inst k) phi).
Proof.
  intros phi rho k.
  rewrite subst_instTerm_var.
  rewrite (rename_hfFormulaAt phi (hfUpVarMap rho) (inst (rho k))).
  transitivity (hfFormulaAt (fun n => rho (Fol.inst k n)) phi).
  - apply hfFormulaAt_ext.
    intros [|n]; reflexivity.
  - symmetry.
    apply hfFormulaAt_source_rename.
Qed.

Lemma hfFormulaAt_eq_translateHFFormula_of_HF_sentence : forall phi rho,
  Fol.Sentence phi -> hfFormulaAt rho phi = translateHFFormula phi.
Proof.
  intros phi rho hphi.
  unfold translateHFFormula.
  apply hfFormulaAt_ext_free.
  intros n hn.
  exfalso.
  exact (hphi n hn).
Qed.

Lemma hfFormulaAt_sentence_of_HF_sentence : forall phi rho,
  Fol.Sentence phi -> Sentence (hfFormulaAt rho phi).
Proof.
  intros phi rho hphi i hi.
  destruct (hfFormulaAt_free phi rho i hi) as [n [hn _]].
  exact (hphi n hn).
Qed.

Lemma translateHFFormula_sentence_of_HF_sentence : forall phi,
  Fol.Sentence phi -> Sentence (translateHFFormula phi).
Proof.
  intros phi hphi.
  apply hfFormulaAt_sentence_of_HF_sentence.
  exact hphi.
Qed.

Lemma translated_HF_axiom_sat_nat : forall phi,
  HFAx_s phi -> forall v, Sat natModel v (translateHFFormula phi).
Proof.
  intros phi hphi v.
  apply (proj2 (translateHFFormula_exact phi v)).
  exact (standard_sat_HF v phi hphi).
Qed.

Lemma translated_HFFin_axiom_sat_nat : forall phi,
  HFFinAx_s phi -> forall v, Sat natModel v (translateHFFormula phi).
Proof.
  intros phi hphi v.
  apply (proj2 (translateHFFormula_exact phi v)).
  exact (standard_sat_HFFin v phi hphi).
Qed.

Lemma translated_HF_axiom_sentence : forall g,
  HFAx_s g -> Sentence (translateHFFormula g).
Proof.
  intros g hg.
  apply translateHFFormula_sentence_of_HF_sentence.
  exact (Sentences_HF g hg).
Qed.

Lemma translated_HFFin_axiom_sentence : forall g,
  HFFinAx_s g -> Sentence (translateHFFormula g).
Proof.
  intros g hg.
  apply translateHFFormula_sentence_of_HF_sentence.
  exact (Sentences_HFFin g hg).
Qed.

Definition translatedHFAx (phi : formula) : Prop :=
  exists g, HFAx_s g /\ phi = translateHFFormula g.

Definition translatedHFFinAx (phi : formula) : Prop :=
  exists g, HFFinAx_s g /\ phi = translateHFFormula g.

Lemma translatedHFAx_intro : forall g,
  HFAx_s g -> translatedHFAx (translateHFFormula g).
Proof.
  intros g hg.
  exists g.
  split; [exact hg | reflexivity].
Qed.

Lemma translatedHFFinAx_intro : forall g,
  HFFinAx_s g -> translatedHFFinAx (translateHFFormula g).
Proof.
  intros g hg.
  exists g.
  split; [exact hg | reflexivity].
Qed.

Lemma translatedHFFinAx_of_translatedHFAx : forall phi,
  translatedHFAx phi -> translatedHFFinAx phi.
Proof.
  intros phi [g [hg hphi]].
  subst phi.
  apply translatedHFFinAx_intro.
  apply HFFinAx_s_of_HFAx_s.
  exact hg.
Qed.

Lemma Sentences_translatedHFAx : forall phi,
  translatedHFAx phi -> Sentence phi.
Proof.
  intros phi [g [hg hphi]].
  subst phi.
  exact (translated_HF_axiom_sentence g hg).
Qed.

Lemma Sentences_translatedHFFinAx : forall phi,
  translatedHFFinAx phi -> Sentence phi.
Proof.
  intros phi [g [hg hphi]].
  subst phi.
  exact (translated_HFFin_axiom_sentence g hg).
Qed.

Lemma BProv_translatedHFAx_of_HFAx : forall g,
  HFAx_s g -> BProv translatedHFAx [] (translateHFFormula g).
Proof.
  intros g hg.
  apply BProv_ax.
  apply translatedHFAx_intro.
  exact hg.
Qed.

Lemma BProv_translatedHFFinAx_of_HFFinAx : forall g,
  HFFinAx_s g -> BProv translatedHFFinAx [] (translateHFFormula g).
Proof.
  intros g hg.
  apply BProv_ax.
  apply translatedHFFinAx_intro.
  exact hg.
Qed.

Lemma BProv_lift_translatedHFAx_to_PA :
  (forall f, translatedHFAx f -> BProv Ax_s [] f) ->
  forall f, BProv translatedHFAx [] f -> BProv Ax_s [] f.
Proof.
  intros hAx f h.
  apply (BProv_lift translatedHFAx Ax_s [] [] f h).
  - intros b hb. exact (hAx b hb).
  - intros g hg. contradiction.
Qed.

Lemma BProv_lift_translatedHFFinAx_to_PA :
  (forall f, translatedHFFinAx f -> BProv Ax_s [] f) ->
  forall f, BProv translatedHFFinAx [] f -> BProv Ax_s [] f.
Proof.
  intros hAx f h.
  apply (BProv_lift translatedHFFinAx Ax_s [] [] f h).
  - intros b hb. exact (hAx b hb).
  - intros g hg. contradiction.
Qed.

Record TranslatedHFAxiomProofs := {
  thf_empty :
    BProv Ax_s [] (translateHFFormula (seal HF_empty_form));
  thf_extensionality :
    BProv Ax_s [] (translateHFFormula (seal HF_extensionality_form));
  thf_adjoin :
    BProv Ax_s [] (translateHFFormula (seal HF_adjoin_form));
  thf_induction : forall phi,
    BProv Ax_s [] (translateHFFormula (seal (HF_induction_form phi)))
}.

Record TranslatedHFFinAxiomProofs := {
  thffin_empty :
    BProv Ax_s [] (translateHFFormula (seal HF_empty_form));
  thffin_extensionality :
    BProv Ax_s [] (translateHFFormula (seal HF_extensionality_form));
  thffin_adjoin :
    BProv Ax_s [] (translateHFFormula (seal HF_adjoin_form));
  thffin_induction : forall phi,
    BProv Ax_s [] (translateHFFormula (seal (HF_induction_form phi)));
  thffin_finite_induction : forall phi,
    BProv Ax_s [] (translateHFFormula (seal (HF_finite_induction_form phi)))
}.

Definition TranslatedHFAxiomProofs_of_TranslatedHFFinAxiomProofs
    (P : TranslatedHFFinAxiomProofs) : TranslatedHFAxiomProofs :=
  {| thf_empty := thffin_empty P;
     thf_extensionality := thffin_extensionality P;
     thf_adjoin := thffin_adjoin P;
     thf_induction := thffin_induction P |}.

Lemma BProv_Ax_s_of_translatedHFAx_of_proofs :
  forall (P : TranslatedHFAxiomProofs) phi,
  translatedHFAx phi -> BProv Ax_s [] phi.
Proof.
  intros P phi [g [hg ->]].
  unfold HFAx_s in hg.
  destruct hg as [hg | [hg | [hg | [psi hg]]]]; subst g.
  - exact (thf_empty P).
  - exact (thf_extensionality P).
  - exact (thf_adjoin P).
  - exact (thf_induction P psi).
Qed.

Lemma BProv_Ax_s_of_translatedHFFinAx_of_proofs :
  forall (P : TranslatedHFFinAxiomProofs) phi,
  translatedHFFinAx phi -> BProv Ax_s [] phi.
Proof.
  intros P phi [g [hg ->]].
  unfold HFFinAx_s in hg.
  destruct hg as [hgHF | [psi hgFin]].
  - apply (BProv_Ax_s_of_translatedHFAx_of_proofs
      (TranslatedHFAxiomProofs_of_TranslatedHFFinAxiomProofs P)).
    apply translatedHFAx_intro.
    exact hgHF.
  - subst g.
    exact (thffin_finite_induction P psi).
Qed.

Lemma standard_sat_translatedHFAx : forall e,
  forall g, translatedHFAx g -> Sat natModel e g.
Proof.
  intros e g [phi [hphi hg]].
  subst g.
  exact (translated_HF_axiom_sat_nat phi hphi e).
Qed.

Lemma standard_sat_translatedHFFinAx : forall e,
  forall g, translatedHFFinAx g -> Sat natModel e g.
Proof.
  intros e g [phi [hphi hg]].
  subst g.
  exact (translated_HFFin_axiom_sat_nat phi hphi e).
Qed.

Lemma Prov_hfFormulaAt_of_Prov : forall G phi,
  Calculus.Prov G phi ->
  forall rho, Prov (hfContextAt rho G) (hfFormulaAt rho phi).
Proof.
  intros G phi h.
  induction h; intro rho; simpl.
  - apply P_ass.
    unfold hfContextAt.
    apply in_map.
    exact H.
  - apply P_impI.
    exact (IHh rho).
  - exact (P_impE _ _ _ (IHh1 rho) (IHh2 rho)).
  - exact (P_botE _ _ (IHh rho)).
  - apply P_lem.
  - exact (P_andI _ _ _ (IHh1 rho) (IHh2 rho)).
  - exact (P_andE1 _ _ _ (IHh rho)).
  - exact (P_andE2 _ _ _ (IHh rho)).
  - exact (P_orI1 _ _ _ (IHh rho)).
  - exact (P_orI2 _ _ _ (IHh rho)).
  - exact (P_orE _ _ _ _ (IHh1 rho) (IHh2 rho) (IHh3 rho)).
  - apply P_allI.
    rewrite <- hfContextAt_rename_succ.
    exact (IHh (hfUpVarMap rho)).
  - pose proof (P_allE _ (hfFormulaAt (hfUpVarMap rho) a)
      (tVar (rho k)) (IHh rho)) as hinst.
    rewrite subst_instTerm_var_hfFormulaAt in hinst.
    exact hinst.
  - apply (P_exI _ (hfFormulaAt (hfUpVarMap rho) a) (tVar (rho k))).
    rewrite subst_instTerm_var_hfFormulaAt.
    exact (IHh rho).
  - apply (P_exE _ (hfFormulaAt (hfUpVarMap rho) a) (hfFormulaAt rho c)).
    + exact (IHh1 rho).
    + rewrite <- hfFormulaAt_rename_succ.
      rewrite <- hfContextAt_cons_rename_succ.
      exact (IHh2 (hfUpVarMap rho)).
  - apply P_eqRefl.
  - assert (hbody : Prov (hfContextAt rho G)
        (subst (instTerm (tVar (rho i))) (hfFormulaAt (hfUpVarMap rho) a))).
    {
      rewrite subst_instTerm_var_hfFormulaAt.
      exact (IHh2 rho).
    }
    pose proof (P_eqElim _ (tVar (rho i)) (tVar (rho j))
      (hfFormulaAt (hfUpVarMap rho) a) (IHh1 rho) hbody) as hmain.
    rewrite subst_instTerm_var_hfFormulaAt in hmain.
    exact hmain.
Qed.

Lemma BProv_hfFormulaAt_of_BProv_HFFin : forall G phi,
  Completeness.BProv HFFinAx_s G phi ->
  forall rho,
    BProv translatedHFFinAx (hfContextAt rho G) (hfFormulaAt rho phi).
Proof.
  intros G phi [L [hL hprov]] rho.
  exists (hfContextAt rho L).
  split.
  - intros f hf.
    unfold hfContextAt in hf.
    apply in_map_iff in hf.
    destruct hf as [g [hf hg]].
    subst f.
    pose proof (hL g hg) as hgAx.
    rewrite (hfFormulaAt_eq_translateHFFormula_of_HF_sentence
      g rho (Sentences_HFFin g hgAx)).
    apply translatedHFFinAx_intro.
    exact hgAx.
  - pose proof (Prov_hfFormulaAt_of_Prov (L ++ G) phi hprov rho) as hp.
    unfold hfContextAt in *.
    rewrite map_app in hp.
    exact hp.
Qed.

Lemma BProv_translateHFFormula_of_BProv_HFFin : forall phi,
  Completeness.BProv HFFinAx_s [] phi ->
  BProv translatedHFFinAx [] (translateHFFormula phi).
Proof.
  intros phi h.
  pose proof (BProv_hfFormulaAt_of_BProv_HFFin [] phi h
    (fun n => n)) as htranslated.
  unfold hfContextAt, translateHFFormula in htranslated.
  simpl in htranslated.
  exact htranslated.
Qed.


(* HF extensionality, distinguisher macros, and their semantics (ported from PASyntax.lean) *)

(* Lean: subst_instTerm_var_hfMemAt_zero_succ *)
Lemma subst_instTerm_var_hfMemAt_zero_succ : forall elem set,
  subst (instTerm (tVar elem)) (hfMemAt 0 (S set)) =
    hfMemAt elem set.
Proof. reflexivity. Qed.

(* Lean: subst_instTerm_var_hfMemTermAt_zero_rename_succ *)
Lemma subst_instTerm_var_hfMemTermAt_zero_rename_succ :
  forall elem setCode,
  subst (instTerm (tVar elem)) (hfMemTermAt 0 (Term.rename S setCode)) =
    hfMemTermAt elem setCode.
Proof.
  intros elem setCode.
  unfold hfMemTermAt, betaTermAtConstIdx, betaTermAt, remTermAt, ltTermAt,
    betaAt, remAt, ltAt, leAt, betaDiv2StepsThroughAt,
    betaDiv2StepWitnessAt, betaDiv2BitAt, betaAtSuccIdx, div2StepAt,
    boolAt, zeroAt, oneAt, eqConstAt, betaModTerm.
  simpl.
  repeat rewrite Term.subst_rename_succ_up.
  repeat rewrite term_subst_instTerm_rename_succ.
  reflexivity.
Qed.

(* Lean: subst_instTerm_var_hfMemAt_iff *)
Lemma subst_instTerm_var_hfMemAt_iff : forall elem left right,
  subst (instTerm (tVar elem))
      (iffForm (hfMemAt 0 (S left)) (hfMemAt 0 (S right))) =
    iffForm (hfMemAt elem left) (hfMemAt elem right).
Proof. reflexivity. Qed.

(* Lean: BProv_hfMemAt_iff_of_all *)
Lemma BProv_hfMemAt_iff_of_all :
  forall (B : formula -> Prop) G elem left right,
  BProv B G (pAll (iffForm (hfMemAt 0 (S left)) (hfMemAt 0 (S right)))) ->
  BProv B G (iffForm (hfMemAt elem left) (hfMemAt elem right)).
Proof.
  intros B G elem left right hsame.
  pose proof (BProv_allE B G
    (iffForm (hfMemAt 0 (S left)) (hfMemAt 0 (S right)))
    (tVar elem) hsame) as hinst.
  rewrite subst_instTerm_var_hfMemAt_iff in hinst.
  exact hinst.
Qed.

(* Lean: BProv_hfMemAt_forward_of_all *)
Lemma BProv_hfMemAt_forward_of_all :
  forall (B : formula -> Prop) G elem left right,
  BProv B G (pAll (iffForm (hfMemAt 0 (S left)) (hfMemAt 0 (S right)))) ->
  BProv B G (pImp (hfMemAt elem left) (hfMemAt elem right)).
Proof.
  intros B G elem left right hsame.
  exact (BProv_andE1 B G
    (pImp (hfMemAt elem left) (hfMemAt elem right))
    (pImp (hfMemAt elem right) (hfMemAt elem left))
    (BProv_hfMemAt_iff_of_all B G elem left right hsame)).
Qed.

(* Lean: BProv_hfMemAt_reverse_of_all *)
Lemma BProv_hfMemAt_reverse_of_all :
  forall (B : formula -> Prop) G elem left right,
  BProv B G (pAll (iffForm (hfMemAt 0 (S left)) (hfMemAt 0 (S right)))) ->
  BProv B G (pImp (hfMemAt elem right) (hfMemAt elem left)).
Proof.
  intros B G elem left right hsame.
  exact (BProv_andE2 B G
    (pImp (hfMemAt elem left) (hfMemAt elem right))
    (pImp (hfMemAt elem right) (hfMemAt elem left))
    (BProv_hfMemAt_iff_of_all B G elem left right hsame)).
Qed.

