Lemma rename_HF_emptyAt : forall (r : nat -> nat) i,
  rename r (HF_emptyAt i) = HF_emptyAt (r i).
Proof.
  intros r i.
  unfold HF_emptyAt.
  simpl.
  reflexivity.
Qed.

